{
  "name": "Quản Lý Ngăn Chặn Đất Đai",
  "description": "Ứng dụng quản lý hồ sơ đất đai, theo dõi tình trạng ngăn chặn và giải tỏa ngăn chặn với giao diện trực quan."
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Không tìm thấy thẻ root để mount ứng dụng");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

import React, { useState, useEffect } from 'react';
import { LandRecord, LandRecordFormData } from '../types';
import { Plus, Trash2, X } from 'lucide-react';

interface RecordFormProps {
  initialData?: LandRecord;
  onSubmit: (data: LandRecordFormData) => void;
  onCancel: () => void;
}

const RecordForm: React.FC<RecordFormProps> = ({ initialData, onSubmit, onCancel }) => {
  // Khởi tạo state cho form
  const [formData, setFormData] = useState<LandRecordFormData>({
    owners: [''],
    issueNumber: '',
    certNumber: '',
    issueDate: new Date().toISOString().split('T')[0],
    area: 0,
    plotNumber: '',
    mapSheetNumber: '',
    hamlet: '',
    oldCommune: '',
    newCommune: '',
    blockDoc: '',
    blockDate: new Date().toISOString().split('T')[0],
    agency: '',
    unblockDoc: '',
    notes: '',
    isUnblocked: false,
  });

  // Nếu đang ở chế độ sửa, nạp dữ liệu cũ vào form
  useEffect(() => {
    if (initialData) {
      setFormData(initialData);
    }
  }, [initialData]);

  // Xử lý thay đổi input cơ bản
  const handleChange = (e: React.ChangeEvent<HTMLInputElement | HTMLTextAreaElement | HTMLSelectElement>) => {
    const { name, value, type } = e.target;

    if (type === 'checkbox') {
      const checked = (e.target as HTMLInputElement).checked;
      setFormData(prev => ({ ...prev, [name]: checked }));
    } else {
      setFormData(prev => ({ ...prev, [name]: value }));
    }
  };

  // Xử lý thay đổi tên chủ sử dụng (mảng)
  const handleOwnerChange = (index: number, value: string) => {
    const newOwners = [...formData.owners];
    newOwners[index] = value;
    setFormData(prev => ({ ...prev, owners: newOwners }));
  };

  const addOwnerField = () => {
    setFormData(prev => ({ ...prev, owners: [...prev.owners, ''] }));
  };

  const removeOwnerField = (index: number) => {
    if (formData.owners.length > 1) {
      const newOwners = formData.owners.filter((_, i) => i !== index);
      setFormData(prev => ({ ...prev, owners: newOwners }));
    }
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    onSubmit(formData);
  };

  return (
    <div className="fixed inset-0 bg-black bg-opacity-50 flex justify-center items-center z-50 p-4 overflow-y-auto">
      <div className="bg-white rounded-lg shadow-xl w-full max-w-4xl max-h-[90vh] overflow-y-auto">
        <div className="flex justify-between items-center p-6 border-b sticky top-0 bg-white z-10">
          <h2 className="text-xl font-bold text-gray-800">
            {initialData ? 'Cập Nhật Hồ Sơ' : 'Thêm Mới Hồ Sơ Ngăn Chặn'}
          </h2>
          <button onClick={onCancel} className="text-gray-500 hover:text-gray-700">
            <X size={24} />
          </button>
        </div>

        <form onSubmit={handleSubmit} className="p-6 grid grid-cols-1 md:grid-cols-2 gap-6">
          {/* Phần 1: Thông tin chủ sở hữu */}
          <div className="md:col-span-2 space-y-3">
            <label className="block text-sm font-medium text-gray-700">Chủ sử dụng đất</label>
            {formData.owners.map((owner, index) => (
              <div key={index} className="flex gap-2">
                <input
                  type="text"
                  required
                  value={owner}
                  onChange={(e) => handleOwnerChange(index, e.target.value)}
                  placeholder={`Tên chủ sử dụng ${index + 1}`}
                  className="flex-1 rounded-md border-gray-300 shadow-sm border p-2 focus:ring-blue-500 focus:border-blue-500"
                />
                {formData.owners.length > 1 && (
                  <button
                    type="button"
                    onClick={() => removeOwnerField(index)}
                    className="text-red-500 hover:text-red-700 p-2"
                  >
                    <Trash2 size={20} />
                  </button>
                )}
              </div>
            ))}
            <button
              type="button"
              onClick={addOwnerField}
              className="flex items-center text-sm text-blue-600 hover:text-blue-800"
            >
              <Plus size={16} className="mr-1" /> Thêm chủ sử dụng
            </button>
          </div>

          {/* Phần 2: Thông tin GCN */}
          <div className="space-y-4 border p-4 rounded-md bg-gray-50">
            <h3 className="font-semibold text-gray-700 border-b pb-2">Thông tin Giấy Chứng Nhận</h3>
            <div>
              <label className="block text-sm font-medium text-gray-700">Số phát hành</label>
              <input
                type="text"
                name="issueNumber"
                value={formData.issueNumber}
                onChange={handleChange}
                className="mt-1 block w-full rounded-md border-gray-300 border p-2 shadow-sm"
              />
            </div>
            <div>
              <label className="block text-sm font-medium text-gray-700">Số vào sổ cấp giấy</label>
              <input
                type="text"
                name="certNumber"
                value={formData.certNumber}
                onChange={handleChange}
                className="mt-1 block w-full rounded-md border-gray-300 border p-2 shadow-sm"
              />
            </div>
            <div>
              <label className="block text-sm font-medium text-gray-700">Ngày cấp</label>
              <input
                type="date"
                name="issueDate"
                value={formData.issueDate}
                onChange={handleChange}
                className="mt-1 block w-full rounded-md border-gray-300 border p-2 shadow-sm"
              />
            </div>
          </div>

          {/* Phần 3: Thông tin thửa đất */}
          <div className="space-y-4 border p-4 rounded-md bg-gray-50">
            <h3 className="font-semibold text-gray-700 border-b pb-2">Thông tin Thửa Đất</h3>
            <div className="grid grid-cols-2 gap-4">
              <div>
                <label className="block text-sm font-medium text-gray-700">Tờ bản đồ số</label>
                <input
                  type="text"
                  name="mapSheetNumber"
                  value={formData.mapSheetNumber}
                  onChange={handleChange}
                  className="mt-1 block w-full rounded-md border-gray-300 border p-2 shadow-sm"
                />
              </div>
              <div>
                <label className="block text-sm font-medium text-gray-700">Thửa đất số</label>
                <input
                  type="text"
                  name="plotNumber"
                  value={formData.plotNumber}
                  onChange={handleChange}
                  className="mt-1 block w-full rounded-md border-gray-300 border p-2 shadow-sm"
                />
              </div>
            </div>
            <div>
              <label className="block text-sm font-medium text-gray-700">Diện tích (m2)</label>
              <input
                type="number"
                name="area"
                value={formData.area}
                onChange={handleChange}
                className="mt-1 block w-full rounded-md border-gray-300 border p-2 shadow-sm"
              />
            </div>
            <div>
              <label className="block text-sm font-medium text-gray-700">Ấp/Khu phố</label>
              <input
                type="text"
                name="hamlet"
                value={formData.hamlet}
                onChange={handleChange}
                className="mt-1 block w-full rounded-md border-gray-300 border p-2 shadow-sm"
              />
            </div>
             <div className="grid grid-cols-2 gap-4">
               <div>
                <label className="block text-sm font-medium text-gray-700">Xã/Phường (Cũ)</label>
                <input
                  type="text"
                  name="oldCommune"
                  value={formData.oldCommune}
                  onChange={handleChange}
                  className="mt-1 block w-full rounded-md border-gray-300 border p-2 shadow-sm"
                />
              </div>
              <div>
                <label className="block text-sm font-medium text-gray-700">Xã/Phường (Mới)</label>
                <input
                  type="text"
                  name="newCommune"
                  value={formData.newCommune}
                  onChange={handleChange}
                  className="mt-1 block w-full rounded-md border-gray-300 border p-2 shadow-sm"
                />
              </div>
             </div>
          </div>

          {/* Phần 4: Thông tin ngăn chặn */}
          <div className="md:col-span-2 space-y-4 border p-4 rounded-md bg-red-50 border-red-100">
            <h3 className="font-semibold text-red-700 border-b border-red-200 pb-2">Thông tin Ngăn Chặn</h3>
            <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
              <div>
                <label className="block text-sm font-medium text-gray-700">Văn bản ngăn chặn</label>
                <input
                  type="text"
                  name="blockDoc"
                  required
                  value={formData.blockDoc}
                  onChange={handleChange}
                  placeholder="Số VB..."
                  className="mt-1 block w-full rounded-md border-gray-300 border p-2 shadow-sm"
                />
              </div>
              <div>
                <label className="block text-sm font-medium text-gray-700">Ngày văn bản</label>
                <input
                  type="date"
                  name="blockDate"
                  value={formData.blockDate}
                  onChange={handleChange}
                  className="mt-1 block w-full rounded-md border-gray-300 border p-2 shadow-sm"
                />
              </div>
              <div>
                <label className="block text-sm font-medium text-gray-700">Cơ quan phát hành</label>
                <input
                  type="text"
                  name="agency"
                  value={formData.agency}
                  onChange={handleChange}
                  className="mt-1 block w-full rounded-md border-gray-300 border p-2 shadow-sm"
                />
              </div>
            </div>

            <div>
              <label className="block text-sm font-medium text-gray-700">Ghi chú</label>
              <textarea
                name="notes"
                rows={2}
                value={formData.notes}
                onChange={handleChange}
                className="mt-1 block w-full rounded-md border-gray-300 border p-2 shadow-sm"
              />
            </div>
          </div>

          {/* Phần 5: Giải tỏa ngăn chặn */}
          <div className="md:col-span-2 space-y-4 border p-4 rounded-md bg-green-50 border-green-100">
             <div className="flex items-center space-x-3 mb-4">
                <input
                  type="checkbox"
                  id="isUnblocked"
                  name="isUnblocked"
                  checked={formData.isUnblocked}
                  onChange={handleChange}
                  className="h-5 w-5 text-green-600 focus:ring-green-500 border-gray-300 rounded"
                />
                <label htmlFor="isUnblocked" className="font-bold text-green-800 text-lg">
                  ĐÃ XÓA NGĂN CHẶN
                </label>
             </div>

             {formData.isUnblocked && (
               <div className="animate-in fade-in slide-in-from-top-4 duration-300">
                  <label className="block text-sm font-medium text-gray-700">Văn bản hủy ngăn chặn</label>
                  <input
                    type="text"
                    name="unblockDoc"
                    value={formData.unblockDoc}
                    onChange={handleChange}
                    placeholder="Nhập số văn bản hủy..."
                    className="mt-1 block w-full rounded-md border-gray-300 border p-2 shadow-sm"
                  />
               </div>
             )}
          </div>

          {/* Nút hành động */}
          <div className="md:col-span-2 flex justify-end gap-3 pt-4 border-t">
            <button
              type="button"
              onClick={onCancel}
              className="px-4 py-2 bg-gray-200 text-gray-700 rounded-md hover:bg-gray-300 transition-colors"
            >
              Hủy bỏ
            </button>
            <button
              type="submit"
              className="px-4 py-2 bg-blue-600 text-white rounded-md hover:bg-blue-700 transition-colors font-medium"
            >
              {initialData ? 'Lưu Thay Đổi' : 'Thêm Mới'}
            </button>
          </div>
        </form>
      </div>
    </div>
  );
};

export default RecordForm;

import React, { useState, useMemo } from 'react';
import { LandRecord, LandRecordFormData } from './types';
import RecordForm from './components/RecordForm';
import { Search, Plus, Edit2, Trash2, FileText, Lock, Unlock, MapPin } from 'lucide-react';

// Dữ liệu mẫu ban đầu
const MOCK_DATA: LandRecord[] = [
  {
    id: '1',
    owners: ['Nguyễn Văn A', 'Trần Thị B'],
    issueNumber: 'AB123456',
    certNumber: 'CH001',
    issueDate: '2020-01-15',
    area: 150.5,
    plotNumber: '12',
    mapSheetNumber: '5',
    hamlet: 'Khu phố 1',
    oldCommune: 'Phường X cũ',
    newCommune: 'Phường Y mới',
    blockDoc: 'CV-100/TA',
    blockDate: '2023-05-20',
    agency: 'Tòa án ND Huyện',
    unblockDoc: '',
    notes: 'Tranh chấp thừa kế',
    isUnblocked: false,
  },
  {
    id: '2',
    owners: ['Lê Văn C'],
    issueNumber: 'CD987654',
    certNumber: 'CH002',
    issueDate: '2019-11-30',
    area: 300,
    plotNumber: '45',
    mapSheetNumber: '10',
    hamlet: 'Ấp 2',
    oldCommune: 'Xã Z',
    newCommune: 'Xã Z',
    blockDoc: 'TB-ThiHanhAn',
    blockDate: '2022-02-15',
    agency: 'Chi cục THADS',
    unblockDoc: 'QD-GiaiToa-01',
    notes: 'Đã giải quyết xong nợ',
    isUnblocked: true,
  },
];

function App() {
  const [records, setRecords] = useState<LandRecord[]>(MOCK_DATA);
  const [isFormOpen, setIsFormOpen] = useState(false);
  const [editingRecord, setEditingRecord] = useState<LandRecord | undefined>(undefined);
  const [searchTerm, setSearchTerm] = useState('');

  // Lọc hồ sơ theo từ khóa
  const filteredRecords = useMemo(() => {
    return records.filter(record => {
      const searchLower = searchTerm.toLowerCase();
      const ownersString = record.owners.join(' ').toLowerCase();
      return (
        ownersString.includes(searchLower) ||
        record.plotNumber.includes(searchLower) ||
        record.mapSheetNumber.includes(searchLower) ||
        record.issueNumber.toLowerCase().includes(searchLower)
      );
    });
  }, [records, searchTerm]);

  // Thống kê
  const stats = useMemo(() => {
    const total = records.length;
    const blocked = records.filter(r => !r.isUnblocked).length;
    const unblocked = total - blocked;
    return { total, blocked, unblocked };
  }, [records]);

  // Handlers
  const handleAddRecord = (data: LandRecordFormData) => {
    const newRecord: LandRecord = {
      ...data,
      id: Date.now().toString(),
    };
    setRecords(prev => [newRecord, ...prev]);
    setIsFormOpen(false);
  };

  const handleUpdateRecord = (data: LandRecordFormData) => {
    if (!editingRecord) return;
    setRecords(prev => prev.map(r => r.id === editingRecord.id ? { ...data, id: editingRecord.id } : r));
    setEditingRecord(undefined);
    setIsFormOpen(false);
  };

  const handleDeleteRecord = (id: string) => {
    if (window.confirm('Bạn có chắc chắn muốn xóa hồ sơ này không?')) {
      setRecords(prev => prev.filter(r => r.id !== id));
    }
  };

  const startEdit = (record: LandRecord) => {
    setEditingRecord(record);
    setIsFormOpen(true);
  };

  return (
    <div className="min-h-screen bg-gray-100 p-4 md:p-8">
      <div className="max-w-7xl mx-auto space-y-6">

        {/* Header */}
        <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4 bg-white p-6 rounded-lg shadow-sm border border-gray-200">
          <div>
            <h1 className="text-2xl font-bold text-gray-800 flex items-center gap-2">
              <FileText className="text-blue-600" />
              Quản Lý Ngăn Chặn Đất Đai
            </h1>
            <p className="text-gray-500 text-sm mt-1">Hệ thống theo dõi và tra cứu hồ sơ biến động</p>
          </div>

          <button
            onClick={() => { setEditingRecord(undefined); setIsFormOpen(true); }}
            className="flex items-center gap-2 bg-blue-600 text-white px-4 py-2 rounded-md hover:bg-blue-700 transition shadow-sm"
          >
            <Plus size={20} />
            Thêm Hồ Sơ Mới
          </button>
        </div>

        {/* Dashboard Stats */}
        <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
          <div className="bg-white p-4 rounded-lg shadow-sm border-l-4 border-blue-500">
            <p className="text-gray-500 text-sm font-medium">Tổng hồ sơ</p>
            <p className="text-3xl font-bold text-gray-800">{stats.total}</p>
          </div>
          <div className="bg-white p-4 rounded-lg shadow-sm border-l-4 border-red-500">
            <p className="text-red-600 text-sm font-medium flex items-center gap-1">
              <Lock size={16} /> Đang Ngăn Chặn
            </p>
            <p className="text-3xl font-bold text-red-700">{stats.blocked}</p>
          </div>
          <div className="bg-white p-4 rounded-lg shadow-sm border-l-4 border-green-500">
            <p className="text-green-600 text-sm font-medium flex items-center gap-1">
              <Unlock size={16} /> Đã Giải Tỏa
            </p>
            <p className="text-3xl font-bold text-green-700">{stats.unblocked}</p>
          </div>
        </div>

        {/* Search Bar */}
        <div className="relative">
          <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none">
            <Search className="h-5 w-5 text-gray-400" />
          </div>
          <input
            type="text"
            className="block w-full pl-10 pr-3 py-3 border border-gray-300 rounded-lg leading-5 bg-white placeholder-gray-500 focus:outline-none focus:placeholder-gray-400 focus:ring-1 focus:ring-blue-500 focus:border-blue-500 sm:text-sm shadow-sm"
            placeholder="Tìm kiếm theo tên chủ, số tờ, số thửa, số phát hành..."
            value={searchTerm}
            onChange={(e) => setSearchTerm(e.target.value)}
          />
        </div>

        {/* Table List */}
        <div className="bg-white shadow-sm rounded-lg overflow-hidden border border-gray-200">
          <div className="overflow-x-auto">
            <table className="min-w-full divide-y divide-gray-200">
              <thead className="bg-gray-50">
                <tr>
                  <th scope="col" className="px-4 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider sticky left-0 bg-gray-50">Chủ Sử Dụng</th>
                  <th scope="col" className="px-4 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Thông Tin Đất</th>
                  <th scope="col" className="px-4 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Vị Trí</th>
                  <th scope="col" className="px-4 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Ngăn Chặn</th>
                  <th scope="col" className="px-4 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Giải Tỏa</th>
                  <th scope="col" className="px-4 py-3 text-right text-xs font-medium text-gray-500 uppercase tracking-wider">Hành Động</th>
                </tr>
              </thead>
              <tbody className="bg-white divide-y divide-gray-200">
                {filteredRecords.length > 0 ? (
                  filteredRecords.map((record) => (
                    <tr 
                      key={record.id} 
                      className={`${record.isUnblocked ? 'bg-green-50/50 hover:bg-green-100/50' : 'bg-red-50 hover:bg-red-100'} transition-colors`}
                    >
                      <td className="px-4 py-4 whitespace-normal min-w-[200px] sticky left-0 z-10" 
                          style={{backgroundColor: 'inherit'}}>
                        <div className="space-y-1">
                          {record.owners.map((owner, idx) => (
                            <div key={idx} className="font-medium text-gray-900 flex items-center gap-1">
                              • {owner}
                            </div>
                          ))}
                          <div className="text-xs text-gray-500 mt-1">
                             GCN: {record.issueNumber} <br/>
                             Số vào sổ: {record.certNumber}
                          </div>
                        </div>
                      </td>
                      <td className="px-4 py-4 whitespace-nowrap text-sm text-gray-600">
                        <div>Tờ: <span className="font-semibold">{record.mapSheetNumber}</span></div>
                        <div>Thửa: <span className="font-semibold">{record.plotNumber}</span></div>
                        <div>DT: {record.area} m²</div>
                      </td>
                      <td className="px-4 py-4 whitespace-nowrap text-sm text-gray-600">
                        <div className="flex items-start gap-1">
                            <MapPin size={14} className="mt-1 flex-shrink-0" />
                            <div>
                                <div>{record.hamlet}</div>
                                <div className="text-xs text-gray-500">{record.newCommune}</div>
                            </div>
                        </div>
                      </td>
                      <td className="px-4 py-4 whitespace-normal min-w-[250px] text-sm">
                         <div className="font-semibold text-red-700">VB: {record.blockDoc}</div>
                         <div className="text-gray-600">Ngày: {record.blockDate}</div>
                         <div className="text-gray-600 text-xs italic">{record.agency}</div>
                         <div className="mt-2 text-xs bg-white/50 p-1 rounded border border-gray-200">
                             Ghi chú: {record.notes}
                         </div>
                      </td>
                      <td className="px-4 py-4 whitespace-nowrap text-sm">
                        {record.isUnblocked ? (
                            <div className="text-green-700">
                                <span className="flex items-center gap-1 font-bold mb-1"><Unlock size={14}/> Đã xóa</span>
                                <div>VB: {record.unblockDoc}</div>
                            </div>
                        ) : (
                            <div className="text-red-600 font-medium flex items-center gap-1">
                                <Lock size={14}/> Đang ngăn chặn
                            </div>
                        )}
                      </td>
                      <td className="px-4 py-4 whitespace-nowrap text-right text-sm font-medium">
                        <div className="flex justify-end gap-2">
                            <button 
                                onClick={() => startEdit(record)}
                                className="text-blue-600 hover:text-blue-900 p-1 hover:bg-blue-100 rounded"
                                title="Chỉnh sửa"
                            >
                                <Edit2 size={18} />
                            </button>
                            <button 
                                onClick={() => handleDeleteRecord(record.id)}
                                className="text-red-600 hover:text-red-900 p-1 hover:bg-red-100 rounded"
                                title="Xóa"
                            >
                                <Trash2 size={18} />
                            </button>
                        </div>
                      </td>
                    </tr>
                  ))
                ) : (
                  <tr>
                    <td colSpan={6} className="px-6 py-10 text-center text-gray-500 italic">
                      Không tìm thấy hồ sơ nào phù hợp.
                    </td>
                  </tr>
                )}
              </tbody>
            </table>
          </div>
          <div className="p-4 border-t border-gray-200 text-xs text-gray-500 bg-gray-50 flex justify-between">
             <span>Hiển thị {filteredRecords.length} / {records.length} hồ sơ</span>
             <span className="italic">Màu đỏ: Đang ngăn chặn | Màu xanh: Đã giải tỏa</span>
          </div>
        </div>
      </div>

      {/* Modal Form */}
      {isFormOpen && (
        <RecordForm
          initialData={editingRecord}
          onSubmit={editingRecord ? handleUpdateRecord : handleAddRecord}
          onCancel={() => { setIsFormOpen(false); setEditingRecord(undefined); }}
        />
      )}
    </div>
  );
}

