              <p className="text-blue-200 text-xs">Sổ theo dõi ngăn chặn & biến động</p>
            </div>
          </div>
          <div className="flex gap-2">
            <button className="flex items-center gap-2 bg-[#00507d] hover:bg-[#006699] px-3 py-1.5 rounded text-xs font-medium transition border border-blue-400">
               <Printer size={14} /> Xuất Báo Cáo
