      const matchesStatus =
        filterStatus === 'all'
          ? true
          : filterStatus === 'blocked'
          ? !record.isUnblocked
          : record.isUnblocked;

      // 3. Lọc theo cơ quan
      const matchesAgency = filterAgency === '' || record.agency === filterAgency;

      // 4. Lọc theo khoảng thời gian (Ngày văn bản ngăn chặn)
      // Sử dụng so sánh chuỗi YYYY-MM-DD
      let matchesDate = true;
      if (dateRange.start && record.blockDate < dateRange.start) matchesDate = false;
      if (dateRange.end && record.blockDate > dateRange.end) matchesDate = false;

      return matchesSearch && matchesStatus && matchesAgency && matchesDate;
    });
  }, [records, searchTerm, filterStatus, filterAgency, dateRange]);

  // Thống kê
  const stats = useMemo(() => {
    const total = records.length;
    const blocked = records.filter(r => !r.isUnblocked).length;
    const unblocked = total - blocked;
    return { total, blocked, unblocked };
  }, [records]);

  // Handlers
  const handleAddRecord = (data: LandRecordFormData) => {
    const newRecord: LandRecord = {
      ...data,
      id: Date.now().toString(),
    };
    setRecords(prev => [newRecord, ...prev]);
    setIsFormOpen(false);
  };

  const handleUpdateRecord = (data: LandRecordFormData) => {
    if (!editingRecord) return;
    setRecords(prev => prev.map(r => r.id === editingRecord.id ? { ...data, id: editingRecord.id } : r));
    setEditingRecord(undefined);
    setIsFormOpen(false);
  };

  const handleDeleteRecord = (id: string) => {
    if (window.confirm('Xác nhận xóa hồ sơ này khỏi hệ thống?')) {
      setRecords(prev => prev.filter(r => r.id !== id));
    }
  };

  const startEdit = (record: LandRecord) => {
    setEditingRecord(record);
    setIsFormOpen(true);
  };

  const resetFilters = () => {
    setFilterStatus('all');
    setFilterAgency('');
    setDateRange({ start: '', end: '' });
    setSearchTerm('');
  };

  return (
