                  <th className="px-3 py-3 border-r border-gray-300 text-left w-64">Chủ Sử Dụng & GCN</th>
                  <th className="px-3 py-3 border-r border-gray-300 text-left w-56">Đặc Điểm & Vị Trí</th>
                  <th className="px-3 py-3 border-r border-gray-300 text-left">Nội Dung Ngăn Chặn</th>
                  <th className="px-3 py-3 border-r border-gray-300 text-center w-32">Trạng Thái</th>
                  {(canEdit || canDelete) && (
                    <th className="px-3 py-3 text-center w-24">Tác Vụ</th>
                  )}
                </tr>
              </thead>
              <tbody className="bg-white divide-y divide-gray-200 text-sm text-gray-800">
                {filteredRecords.length > 0 ? (
                  filteredRecords.map((record, index) => (
                    <tr 
                      key={record.id} 
                      className={`hover:bg-blue-50 transition-colors ${!record.isUnblocked ? 'bg-red-50/30' : ''}`}
                    >
                      <td className="px-3 py-2 border-r border-gray-300 text-center font-medium text-gray-500">
                        {index + 1}
                      </td>
                      <td className="px-3 py-2 border-r border-gray-300 align-top">
                        <div className="font-bold text-[#003b5c] uppercase mb-1">
                          {record.owners.join(', ')}
                        </div>
                        <div className="text-xs space-y-0.5 text-gray-600">
                             <div className="flex justify-between"><span>Số PH:</span> <span className="font-medium text-black">{record.issueNumber}</span></div>
                             <div className="flex justify-between"><span>Số vào sổ:</span> <span className="font-medium text-black">{record.certNumber}</span></div>
                             <div className="flex justify-between"><span>Ngày cấp:</span> <span>{record.issueDate}</span></div>
                        </div>
                      </td>
                      <td className="px-3 py-2 border-r border-gray-300 align-top">
                        {/* Thông tin kỹ thuật */}
                        <div className="grid grid-cols-2 gap-2 text-xs mb-2 pb-2 border-b border-gray-200">
                           <div className="bg-gray-50 border border-gray-200 rounded p-1 text-center">
                              <span className="block text-[10px] text-gray-500 uppercase">Tờ số</span>
                              <b className="text-black text-sm">{record.mapSheetNumber}</b>
                           </div>
                           <div className="bg-gray-50 border border-gray-200 rounded p-1 text-center">
                              <span className="block text-[10px] text-gray-500 uppercase">Thửa số</span>
                              <b className="text-black text-sm">{record.plotNumber}</b>
                           </div>
                           <div className="col-span-2 text-center text-xs">
                              Diện tích: <b className="text-[#003b5c]">{record.area}</b> m²
                           </div>
                        </div>

                        {/* Thông tin địa chính phân tách rõ ràng */}
                        <div className="text-xs space-y-1">
                             <div className="flex items-start gap-1 font-semibold text-gray-800">
                                <MapPin size={12} className="mt-0.5 text-red-500 flex-shrink-0"/>
                                <span>{record.hamlet}</span>
                             </div>

                             <div className="flex flex-col gap-1 mt-1">
                                <div className="flex items-center justify-between bg-gray-100 px-2 py-1 rounded border border-gray-200">
                                    <span className="text-[9px] font-bold text-gray-500 uppercase w-8">CŨ</span>
                                    <span className="text-gray-600 italic text-right flex-1">{record.oldCommune}</span>
                                </div>

                                <div className="flex justify-center text-gray-400 -my-1.5 z-10">
                                   <ArrowRight size={10} className="rotate-90"/>
                                </div>

                                <div className="flex items-center justify-between bg-blue-50 px-2 py-1 rounded border border-blue-100">
                                    <span className="text-[9px] font-bold text-blue-600 uppercase w-8">MỚI</span>
                                    <span className="text-blue-800 font-bold text-right flex-1">{record.newCommune}</span>
                                </div>
                             </div>
                        </div>
                      </td>
                      <td className="px-3 py-2 border-r border-gray-300 align-top">
                         <div className="mb-2">
                             <div className="text-red-700 font-semibold text-xs uppercase flex items-center gap-1">
                                <FileText size={12}/> VB Ngăn chặn: {record.blockDoc}
                             </div>
                             <div className="text-xs ml-4">
                                <span>Ngày: {record.blockDate}</span> - <span className="font-medium">{record.agency}</span>
                             </div>
                         </div>

                         {record.isUnblocked && (
                           <div className="mt-2 pt-2 border-t border-dashed border-gray-300">
                               <div className="text-green-700 font-semibold text-xs uppercase flex items-center gap-1">
                                  <Unlock size={12}/> VB Hủy bỏ: {record.unblockDoc}
                                </div>
                           </div>
                         )}

                         {record.notes && (
                            <div className="mt-2 text-xs bg-yellow-50 text-yellow-800 p-1.5 border border-yellow-200 rounded-sm italic">
                                Lưu ý: {record.notes}
                            </div>
                         )}
                      </td>
                      <td className="px-3 py-2 border-r border-gray-300 text-center align-middle">
                        {record.isUnblocked ? (
                            <span className="inline-flex items-center px-2.5 py-1 rounded border border-green-200 bg-green-100 text-green-800 text-xs font-bold uppercase tracking-wide">
                                Đã giải ngăn chặn
                            </span>
                        ) : (
                            <span className="inline-flex items-center px-2.5 py-1 rounded border border-red-200 bg-red-100 text-red-800 text-xs font-bold uppercase tracking-wide animate-pulse">
                                Ngăn chặn
                            </span>
                        )}
                      </td>
                      {(canEdit || canDelete) && (
                        <td className="px-3 py-2 text-center align-middle">
                            <div className="flex justify-center gap-1">
                                {canEdit && (
                                    <button 
                                        onClick={() => startEdit(record)}
                                        className="text-blue-600 hover:text-white hover:bg-blue-600 p-1.5 rounded transition"
                                        title="Chỉnh sửa hồ sơ"
                                    >
                                        <Edit size={16} />
                                    </button>
                                )}
                                {canDelete && (
                                    <button 
                                        onClick={() => handleDeleteRecord(record.id)}
                                        className="text-gray-500 hover:text-white hover:bg-red-600 p-1.5 rounded transition"
                                        title="Xóa hồ sơ"
                                    >
                                        <Trash2 size={16} />
                                    </button>
                                )}
                            </div>
                        </td>
                      )}
                    </tr>
                  ))
                ) : (
                  <tr>
                    <td colSpan={canEdit || canDelete ? 6 : 5} className="px-6 py-10 text-center text-gray-500 italic">
                      Không tìm thấy hồ sơ nào phù hợp với các tiêu chí tìm kiếm.
                    </td>
                  </tr>
                )}
              </tbody>
            </table>
          </div>
          <div className="p-2 border-t border-gray-300 text-xs text-gray-600 bg-gray-50 flex justify-between items-center">
             <span>Tổng số: <b>{filteredRecords.length}</b> bản ghi</span>
             <span className="italic opacity-70">Hệ thống quản lý đất đai v1.0</span>
          </div>
        </div>
      </main>

      {/* Modal Form */}
      {isFormOpen && (
        <RecordForm
          initialData={editingRecord}
          onSubmit={editingRecord ? handleUpdateRecord : handleAddRecord}
          onCancel={() => { setIsFormOpen(false); setEditingRecord(undefined); }}
        />
      )}
    </div>
  );
}

export default App;

import React, { useState, useEffect } from 'react';
import { LandRecord, LandRecordFormData } from '../types';
import { Plus, Trash2, X, Save, AlertCircle } from 'lucide-react';

interface RecordFormProps {
  initialData?: LandRecord;
  onSubmit: (data: LandRecordFormData) => void;
  onCancel: () => void;
}

const RecordForm: React.FC<RecordFormProps> = ({ initialData, onSubmit, onCancel }) => {
  const [formData, setFormData] = useState<LandRecordFormData>({
    owners: [''],
    issueNumber: '',
    certNumber: '',
    issueDate: new Date().toISOString().split('T')[0],
    area: 0,
    plotNumber: '',
    mapSheetNumber: '',
    hamlet: '',
    oldCommune: '',
    newCommune: '',
    blockDoc: '',
    blockDate: new Date().toISOString().split('T')[0],
    agency: '',
    unblockDoc: '',
    notes: '',
    isUnblocked: false,
  });

  useEffect(() => {
    if (initialData) {
      setFormData(initialData);
    }
  }, [initialData]);

  const handleChange = (e: React.ChangeEvent<HTMLInputElement | HTMLTextAreaElement | HTMLSelectElement>) => {
    const { name, value, type } = e.target;
    if (type === 'checkbox') {
      const checked = (e.target as HTMLInputElement).checked;
      setFormData(prev => ({ ...prev, [name]: checked }));
    } else {
      setFormData(prev => ({ ...prev, [name]: value }));
    }
  };

  const handleOwnerChange = (index: number, value: string) => {
    const newOwners = [...formData.owners];
    newOwners[index] = value;
    setFormData(prev => ({ ...prev, owners: newOwners }));
  };

  const addOwnerField = () => {
    setFormData(prev => ({ ...prev, owners: [...prev.owners, ''] }));
  };

  const removeOwnerField = (index: number) => {
    if (formData.owners.length > 1) {
      const newOwners = formData.owners.filter((_, i) => i !== index);
      setFormData(prev => ({ ...prev, owners: newOwners }));
    }
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    onSubmit(formData);
  };

  return (
    <div className="fixed inset-0 bg-black/60 flex justify-center items-center z-50 p-4 font-sans">
      <div className="bg-white shadow-2xl w-full max-w-4xl max-h-[95vh] flex flex-col rounded-sm overflow-hidden">
        {/* Header Modal */}
        <div className="flex justify-between items-center px-6 py-4 bg-[#003b5c] text-white border-b border-blue-800 shrink-0">
          <div>
            <h2 className="text-lg font-bold uppercase tracking-wide">
              {initialData ? 'CẬP NHẬT THÔNG TIN HỒ SƠ' : 'NHẬP LIỆU HỒ SƠ NGĂN CHẶN MỚI'}
            </h2>
            <p className="text-xs text-blue-200 opacity-80">Vui lòng nhập đầy đủ thông tin chính xác theo văn bản</p>
          </div>
          <button onClick={onCancel} className="text-white hover:text-red-300 transition-colors">
            <X size={24} />
          </button>
        </div>

        {/* Form Body */}
        <div className="flex-1 overflow-y-auto bg-gray-50 p-6">
          <form id="recordForm" onSubmit={handleSubmit} className="space-y-6">

            {/* Group 1: Thông tin chủ & GCN */}
            <div className="bg-white border border-gray-300 shadow-sm rounded-sm">
                <div className="bg-gray-100 px-4 py-2 border-b border-gray-300 font-bold text-[#003b5c] text-sm uppercase flex items-center gap-2">
                    <span className="bg-[#003b5c] text-white w-6 h-6 flex items-center justify-center rounded-full text-xs">1</span>
                    Thông tin Chủ Sử Dụng & Giấy Chứng Nhận
                </div>
                <div className="p-4 grid grid-cols-1 md:grid-cols-2 gap-4">
                     <div className="md:col-span-2 space-y-2">
                        <label className="block text-xs font-bold text-gray-700 uppercase">Tên chủ sử dụng (Viết hoa)</label>
                        {formData.owners.map((owner, index) => (
                          <div key={index} className="flex gap-2">
                            <input
                              type="text"
                              required
                              value={owner}
                              onChange={(e) => handleOwnerChange(index, e.target.value.toUpperCase())}
                              placeholder="NGUYỄN VĂN A"
                              className="flex-1 border border-gray-300 px-3 py-2 text-sm rounded-sm focus:ring-1 focus:ring-blue-600 focus:border-blue-600 outline-none uppercase"
                            />
                            {formData.owners.length > 1 && (
                              <button
                                type="button"
                                onClick={() => removeOwnerField(index)}
                                className="text-red-500 hover:bg-red-50 px-2 rounded border border-transparent hover:border-red-200"
                              >
                                <Trash2 size={16} />
                              </button>
                            )}
                          </div>
                        ))}
                        <button
                          type="button"
                          onClick={addOwnerField}
                          className="text-xs text-blue-700 hover:underline flex items-center gap-1 font-medium mt-1"
                        >
                          <Plus size={12} /> Thêm đồng sở hữu
                        </button>
                     </div>

                     <div className="grid grid-cols-3 gap-3 md:col-span-2 border-t border-gray-100 pt-3 mt-1">
                        <div>
                            <label className="block text-xs font-semibold text-gray-600 mb-1">Số phát hành (Serial)</label>
                            <input
                                type="text"
                                name="issueNumber"
                                value={formData.issueNumber}
                                onChange={handleChange}
                                className="w-full border border-gray-300 px-3 py-2 text-sm rounded-sm focus:border-blue-600 outline-none"
                            />
                        </div>
                        <div>
                            <label className="block text-xs font-semibold text-gray-600 mb-1">Số vào sổ cấp GCN</label>
                            <input
                                type="text"
                                name="certNumber"
                                value={formData.certNumber}
                                onChange={handleChange}
                                className="w-full border border-gray-300 px-3 py-2 text-sm rounded-sm focus:border-blue-600 outline-none"
                            />
                        </div>
                        <div>
                            <label className="block text-xs font-semibold text-gray-600 mb-1">Ngày cấp</label>
                            <input
                                type="date"
                                name="issueDate"
                                value={formData.issueDate}
                                onChange={handleChange}
                                className="w-full border border-gray-300 px-3 py-2 text-sm rounded-sm focus:border-blue-600 outline-none"
                            />
                        </div>
                     </div>
                </div>
            </div>

            {/* Group 2: Thông tin thửa đất */}
            <div className="bg-white border border-gray-300 shadow-sm rounded-sm">
                <div className="bg-gray-100 px-4 py-2 border-b border-gray-300 font-bold text-[#003b5c] text-sm uppercase flex items-center gap-2">
                    <span className="bg-[#003b5c] text-white w-6 h-6 flex items-center justify-center rounded-full text-xs">2</span>
                    Đặc điểm Thửa Đất
                </div>
                <div className="p-4 grid grid-cols-1 md:grid-cols-3 gap-4">
                     <div>
                        <label className="block text-xs font-semibold text-gray-600 mb-1">Tờ bản đồ số</label>
                        <input
                            type="text"
                            name="mapSheetNumber"
                            value={formData.mapSheetNumber}
                            onChange={handleChange}
                            className="w-full border border-gray-300 px-3 py-2 text-sm rounded-sm focus:border-blue-600 outline-none font-medium"
                        />
                     </div>
                     <div>
                        <label className="block text-xs font-semibold text-gray-600 mb-1">Thửa đất số</label>
                        <input
                            type="text"
                            name="plotNumber"
                            value={formData.plotNumber}
                            onChange={handleChange}
                            className="w-full border border-gray-300 px-3 py-2 text-sm rounded-sm focus:border-blue-600 outline-none font-medium"
                        />
                     </div>
                     <div>
                        <label className="block text-xs font-semibold text-gray-600 mb-1">Diện tích (m²)</label>
                        <input
                            type="number"
                            name="area"
                            value={formData.area}
                            onChange={handleChange}
                            className="w-full border border-gray-300 px-3 py-2 text-sm rounded-sm focus:border-blue-600 outline-none"
                        />
                     </div>

                     <div className="md:col-span-3 grid grid-cols-3 gap-3">
                         <div className="col-span-1">
                            <label className="block text-xs font-semibold text-gray-600 mb-1">Ấp/Khu phố</label>
                            <input
                                type="text"
                                name="hamlet"
                                value={formData.hamlet}
                                onChange={handleChange}
                                className="w-full border border-gray-300 px-3 py-2 text-sm rounded-sm focus:border-blue-600 outline-none"
                            />
                         </div>
                         <div className="col-span-1">
                            <label className="block text-xs font-semibold text-gray-600 mb-1">Xã/Phường (Trước sát nhập)</label>
                            <input
                                type="text"
                                name="oldCommune"
                                value={formData.oldCommune}
                                onChange={handleChange}
                                className="w-full border border-gray-300 px-3 py-2 text-sm rounded-sm focus:border-blue-600 outline-none italic"
                            />
                         </div>
                         <div className="col-span-1">
                            <label className="block text-xs font-semibold text-gray-600 mb-1">Xã/Phường (Hiện tại)</label>
                            <input
                                type="text"
                                name="newCommune"
                                value={formData.newCommune}
                                onChange={handleChange}
                                className="w-full border border-gray-300 px-3 py-2 text-sm rounded-sm focus:border-blue-600 outline-none"
                            />
                         </div>
                     </div>
                </div>
            </div>

            {/* Group 3: Tình trạng ngăn chặn */}
            <div className="bg-white border border-gray-300 shadow-sm rounded-sm">
                <div className="bg-red-50 px-4 py-2 border-b border-red-200 font-bold text-red-800 text-sm uppercase flex items-center gap-2">
                    <span className="bg-red-700 text-white w-6 h-6 flex items-center justify-center rounded-full text-xs">3</span>
                    Nội dung Ngăn Chặn
                </div>
                <div className="p-4 grid grid-cols-1 md:grid-cols-3 gap-4">
                     <div className="md:col-span-2">
                        <label className="block text-xs font-bold text-red-700 mb-1 uppercase">Số văn bản ngăn chặn (*)</label>
                        <input
                            type="text"
                            name="blockDoc"
                            required
                            value={formData.blockDoc}
                            onChange={handleChange}
                            className="w-full border border-red-300 bg-red-50 px-3 py-2 text-sm rounded-sm focus:border-red-600 outline-none font-semibold text-red-900"
                            placeholder="Nhập số công văn/quyết định..."
                        />
                     </div>
                     <div>
                        <label className="block text-xs font-semibold text-gray-600 mb-1">Ngày văn bản</label>
                        <input
                            type="date"
                            name="blockDate"
                            value={formData.blockDate}
                            onChange={handleChange}
                            className="w-full border border-gray-300 px-3 py-2 text-sm rounded-sm focus:border-blue-600 outline-none"
                        />
                     </div>
                     <div className="md:col-span-3">
                        <label className="block text-xs font-semibold text-gray-600 mb-1">Cơ quan ban hành</label>
                        <input
                            type="text"
                            name="agency"
                            value={formData.agency}
                            onChange={handleChange}
                            className="w-full border border-gray-300 px-3 py-2 text-sm rounded-sm focus:border-blue-600 outline-none"
                            placeholder="Ví dụ: Tòa án nhân dân huyện..."
                        />
                     </div>
                     <div className="md:col-span-3">
                        <label className="block text-xs font-semibold text-gray-600 mb-1">Ghi chú thêm</label>
                        <textarea
                            name="notes"
                            rows={2}
                            value={formData.notes}
                            onChange={handleChange}
                            className="w-full border border-gray-300 px-3 py-2 text-sm rounded-sm focus:border-blue-600 outline-none"
                        />
                     </div>
                </div>
            </div>

            {/* Group 4: Giải tỏa */}
            <div className={`border shadow-sm rounded-sm transition-colors ${formData.isUnblocked ? 'bg-green-50 border-green-300' : 'bg-gray-50 border-gray-200'}`}>
                <div className="px-4 py-3 flex items-center justify-between">
                    <div className="flex items-center gap-3">
                        <input
                            type="checkbox"
                            id="isUnblocked"
                            name="isUnblocked"
                            checked={formData.isUnblocked}
                            onChange={handleChange}
                            className="h-5 w-5 text-green-600 focus:ring-green-500 border-gray-300 rounded cursor-pointer"
                        />
                        <label htmlFor="isUnblocked" className={`font-bold uppercase text-sm cursor-pointer select-none ${formData.isUnblocked ? 'text-green-800' : 'text-gray-500'}`}>
                            Đã có văn bản giải ngăn chặn / Hủy ngăn chặn
                        </label>
                    </div>
                </div>

                {formData.isUnblocked && (
                    <div className="p-4 border-t border-green-200 animate-in fade-in slide-in-from-top-2 duration-200">
                        <label className="block text-xs font-bold text-green-800 mb-1 uppercase">Số văn bản hủy bỏ / Giải tỏa</label>
                        <input
                            type="text"
                            name="unblockDoc"
                            value={formData.unblockDoc}
                            onChange={handleChange}
                            className="w-full border border-green-300 px-3 py-2 text-sm rounded-sm focus:border-green-600 outline-none font-medium"
                            placeholder="Nhập số văn bản..."
                            required={formData.isUnblocked}
                        />
                    </div>
                )}
            </div>

          </form>
        </div>

        {/* Footer Actions */}
        <div className="p-4 border-t border-gray-200 bg-gray-50 flex justify-end gap-3 shrink-0">
          <button
            type="button"
            onClick={onCancel}
            className="px-5 py-2 bg-white text-gray-700 border border-gray-300 rounded-sm hover:bg-gray-100 transition-colors text-sm font-medium uppercase"
          >
            Đóng
          </button>
          <button
            type="submit"
            form="recordForm"
            className="px-5 py-2 bg-[#00507d] text-white rounded-sm hover:bg-[#003b5c] transition-colors text-sm font-bold uppercase shadow-sm flex items-center gap-2"
          >
            <Save size={16} /> Lưu Dữ Liệu
          </button>
        </div>
      </div>
    </div>
  );
};

export default RecordForm;

// Định nghĩa chi tiết văn bản ngăn chặn
export interface BlockingDocument {
  docNumber: string; // Số hiệu văn bản
  date: string; // Ngày ban hành
  agency: string; // Cơ quan ban hành
}

// Định nghĩa cấu trúc dữ liệu cho một hồ sơ đất đai
export interface LandRecord {
  id: string;
  owners: string[]; // Mảng chứa tên các chủ sử dụng
  issueNumber: string; // Số phát hành (Serial sổ đỏ)
  certNumber: string; // Số vào sổ cấp giấy
  issueDate: string; // Ngày cấp
  area: number; // Diện tích (m2)
  plotNumber: string; // Số thửa
  mapSheetNumber: string; // Số tờ
  hamlet: string; // Ấp/Khu phố
  oldCommune: string; // Xã/Phường trước sát nhập
  newCommune: string; // Xã/Phường sau sát nhập

  // Thay đổi: Hỗ trợ nhiều văn bản ngăn chặn
  blockingDocuments: BlockingDocument[];

  unblockDoc: string; // Văn bản hủy ngăn chặn (nếu có)
  notes: string; // Ghi chú
  isUnblocked: boolean; // Trạng thái: true = đã giải tỏa, false = đang ngăn chặn
}

// Kiểu dữ liệu cho Form (không có ID vì ID tự sinh)
export type LandRecordFormData = Omit<LandRecord, 'id'>;

// Định nghĩa Role và User
export type UserRole = 'admin' | 'subadmin' | 'user';

export interface User {
  username: string;
  name: string;
  role: UserRole;
}

import React, { useState, useMemo } from 'react';
import { LandRecord, LandRecordFormData, User } from './types';
import RecordForm from './components/RecordForm';
import LoginForm from './components/LoginForm';
import { Search, Plus, Edit, Trash2, FileText, Lock, Unlock, MapPin, Printer, ArrowRight, Filter, XCircle, LogOut, UserCircle, Calendar, Building2 } from 'lucide-react';

// Dữ liệu mẫu ban đầu (Đã cập nhật cấu trúc mảng)
const MOCK_DATA: LandRecord[] = [
  {
    id: '1',
    owners: ['NGUYỄN VĂN A', 'TRẦN THỊ B'],
    issueNumber: 'AB 123456',
    certNumber: 'CH001',
    issueDate: '2020-01-15',
    area: 150.5,
    plotNumber: '12',
    mapSheetNumber: '5',
    hamlet: 'Khu phố 1',
    oldCommune: 'Phường X cũ',
    newCommune: 'Phường Y mới',
    blockingDocuments: [
        { docNumber: 'CV-100/TA', date: '2023-05-20', agency: 'Tòa án ND Huyện' }
    ],
    unblockDoc: '',
    notes: 'Tranh chấp thừa kế',
    isUnblocked: false,
  },
  {
    id: '2',
    owners: ['LÊ VĂN C'],
    issueNumber: 'CD 987654',
    certNumber: 'CH002',
    issueDate: '2019-11-30',
    area: 300,
    plotNumber: '45',
    mapSheetNumber: '10',
    hamlet: 'Ấp 2',
    oldCommune: 'Xã Z',
    newCommune: 'Xã Z',
    blockingDocuments: [
        { docNumber: 'TB-ThiHanhAn', date: '2022-02-15', agency: 'Chi cục THADS' },
        { docNumber: 'CV-BoSung-01', date: '2022-03-01', agency: 'Chi cục THADS' }
    ],
    unblockDoc: 'QD-GiaiToa-01',
    notes: 'Đã giải quyết xong nợ',
    isUnblocked: true,
  },
];

function App() {
  const [currentUser, setCurrentUser] = useState<User | null>(null);
  const [records, setRecords] = useState<LandRecord[]>(MOCK_DATA);
  const [isFormOpen, setIsFormOpen] = useState(false);
  const [editingRecord, setEditingRecord] = useState<LandRecord | undefined>(undefined);

  // State tìm kiếm và lọc
  const [searchTerm, setSearchTerm] = useState('');
  const [showFilters, setShowFilters] = useState(false);
  const [filterStatus, setFilterStatus] = useState<'all' | 'blocked' | 'unblocked'>('all');
  const [filterAgency, setFilterAgency] = useState('');
  const [dateRange, setDateRange] = useState<{ start: string; end: string }>({ start: '', end: '' });

  // State lọc xã phường mới
  const [filterOldCommune, setFilterOldCommune] = useState('');
  const [filterNewCommune, setFilterNewCommune] = useState('');

  // Danh sách cơ quan duy nhất (Lấy từ mảng blockingDocuments)
  const uniqueAgencies = useMemo(() => {
    const agencies = records.flatMap(r => r.blockingDocuments.map(doc => doc.agency));
    return Array.from(new Set(agencies.filter(Boolean))).sort();
  }, [records]);

  // Lọc hồ sơ tổng hợp
  const filteredRecords = useMemo(() => {
    return records.filter(record => {
      // 1. Tìm kiếm từ khóa chung
      const searchLower = searchTerm.toLowerCase();
      const ownersString = record.owners.join(' ').toLowerCase();
      // Kiểm tra xem có văn bản nào khớp số hiệu không
      const hasMatchingDoc = record.blockingDocuments.some(doc => doc.docNumber.toLowerCase().includes(searchLower));

      const matchesSearch = (
        ownersString.includes(searchLower) ||
        record.plotNumber.includes(searchLower) ||
        record.mapSheetNumber.includes(searchLower) ||
        record.issueNumber.toLowerCase().includes(searchLower) ||
        record.certNumber.toLowerCase().includes(searchLower) ||
        hasMatchingDoc
      );

      // 2. Lọc theo trạng thái
      const matchesStatus =
        filterStatus === 'all'
          ? true
          : filterStatus === 'blocked'
          ? !record.isUnblocked
          : record.isUnblocked;

      // 3. Lọc theo cơ quan (Kiểm tra trong mảng văn bản)
      const matchesAgency = filterAgency === '' || record.blockingDocuments.some(doc => doc.agency === filterAgency);

      // 4. Lọc theo khoảng thời gian (Kiểm tra bất kỳ văn bản nào nằm trong khoảng)
      let matchesDate = true;
      if (dateRange.start || dateRange.end) {
          const hasDateInRange = record.blockingDocuments.some(doc => {
              if (dateRange.start && doc.date < dateRange.start) return false;
              if (dateRange.end && doc.date > dateRange.end) return false;
              return true;
          });
          if (!hasDateInRange) matchesDate = false;
      }

      // 5. Lọc theo Xã/Phường
      const matchesOldCommune = record.oldCommune.toLowerCase().includes(filterOldCommune.toLowerCase());
      const matchesNewCommune = record.newCommune.toLowerCase().includes(filterNewCommune.toLowerCase());

      return matchesSearch && matchesStatus && matchesAgency && matchesDate && matchesOldCommune && matchesNewCommune;
    });
  }, [records, searchTerm, filterStatus, filterAgency, dateRange, filterOldCommune, filterNewCommune]);

  // Thống kê
  const stats = useMemo(() => {
    const total = records.length;
    const blocked = records.filter(r => !r.isUnblocked).length;
    const unblocked = total - blocked;
    return { total, blocked, unblocked };
  }, [records]);

  // --- Handlers ---
  const handleLogout = () => setCurrentUser(null);

  const handleAddRecord = (data: LandRecordFormData) => {
    const newRecord: LandRecord = { ...data, id: Date.now().toString() };
    setRecords(prev => [newRecord, ...prev]);
    setIsFormOpen(false);
  };

  const handleUpdateRecord = (data: LandRecordFormData) => {
    if (!editingRecord) return;
    setRecords(prev => prev.map(r => r.id === editingRecord.id ? { ...data, id: editingRecord.id } : r));
    setEditingRecord(undefined);
    setIsFormOpen(false);
  };

  const handleDeleteRecord = (id: string) => {
    if (window.confirm('Xác nhận xóa hồ sơ này khỏi hệ thống? Hành động này không thể hoàn tác.')) {
      setRecords(prev => prev.filter(r => r.id !== id));
    }
  };

  const startEdit = (record: LandRecord) => {
    setEditingRecord(record);
    setIsFormOpen(true);
  };

  const resetFilters = () => {
    if (window.confirm('Bạn có chắc chắn muốn xóa toàn bộ điều kiện lọc và quay về danh sách mặc định?')) {
        setFilterStatus('all');
        setFilterAgency('');
        setDateRange({ start: '', end: '' });
        setSearchTerm('');
        setFilterOldCommune('');
        setFilterNewCommune('');
    }
  };

  const handleExportCSV = () => {
    if (filteredRecords.length === 0) {
      alert('Không có dữ liệu để xuất.');
      return;
    }

    // Hàm hỗ trợ escape chuỗi CSV (xử lý dấu phẩy, dấu ngoặc kép)
    const escapeCsv = (str: string | number | null | undefined) => {
      if (str === null || str === undefined) return '""';
      const stringValue = String(str);
      const escaped = stringValue.replace(/"/g, '""');
      return `"${escaped}"`;
    };

    const headers = [
      "STT", "Chủ Sử Dụng", "Số Phát Hành", "Số Vào Sổ", "Ngày Cấp",
      "Diện Tích (m2)", "Tờ Số", "Thửa Số", "Địa Chỉ",
      "Xã/Phường Cũ", "Xã/Phường Mới",
      "Danh Sách VB Ngăn Chặn (Số - Ngày - Cơ quan)", 
      "Văn Bản Giải Ngăn Chặn", "Trạng Thái", "Ghi Chú"
    ];

    const rows = filteredRecords.map((record, index) => {
       // Gộp danh sách văn bản thành 1 chuỗi, ngăn cách bằng xuống dòng
       const docString = record.blockingDocuments.map(d => `${d.docNumber} (${d.date}) - ${d.agency}`).join('; ');

       return [
        index + 1,
        record.owners.join(', '),
        record.issueNumber,
        record.certNumber,
        record.issueDate,
        record.area,
        record.mapSheetNumber,
        record.plotNumber,
        record.hamlet,
        record.oldCommune,
        record.newCommune,
        docString,
        record.unblockDoc,
        record.isUnblocked ? 'Đã giải ngăn chặn' : 'Đang ngăn chặn',
        record.notes
      ].map(escapeCsv).join(',');
    });

    const csvContent = [headers.join(','), ...rows].join('\n');

    // Thêm BOM (\uFEFF) để Excel nhận diện đúng tiếng Việt (UTF-8)
    const blob = new Blob(['\uFEFF' + csvContent], { type: 'text/csv;charset=utf-8;' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    link.download = `Bao_cao_ngan_chan_${new Date().toISOString().split('T')[0]}.csv`;
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  // --- Permission Checks ---
  // Admin: Toàn quyền
  // Subadmin: Xem, Tìm, Thêm, Sửa (Không Xóa)
  // User: Chỉ Xem, Tìm
  const canAdd = currentUser?.role === 'admin' || currentUser?.role === 'subadmin';
  const canEdit = currentUser?.role === 'admin' || currentUser?.role === 'subadmin';
  const canDelete = currentUser?.role === 'admin';

  // Nếu chưa đăng nhập, hiển thị form login
  if (!currentUser) {
    return <LoginForm onLogin={setCurrentUser} />;
  }

  return (
    <div className="min-h-screen bg-gray-100 flex flex-col font-sans text-sm">
      {/* Administrative Header */}
      <header className="bg-[#003b5c] text-white shadow-md">
        <div className="max-w-[1400px] mx-auto px-4 py-3 flex justify-between items-center">
          <div className="flex items-center gap-3">
            <div className="bg-white p-2 rounded-full shadow-inner">
               <FileText className="text-[#003b5c]" size={24} />
            </div>
            <div>
              <h1 className="text-lg font-bold uppercase tracking-wide">Hệ Thống Quản Lý Ngăn Chặn Đất Đai</h1>
              <p className="text-blue-200 text-xs">Sổ theo dõi ngăn chặn & biến động</p>
            </div>
          </div>

          {/* User Info & Logout */}
          <div className="flex items-center gap-4">
            <button 
                onClick={handleExportCSV}
                className="flex items-center gap-2 bg-[#00507d] hover:bg-[#006699] px-3 py-1.5 rounded text-xs font-medium transition border border-blue-400"
                title="Xuất dữ liệu hiện tại ra file CSV"
            >
                <Printer size={14} /> Xuất Báo Cáo
            </button>
            <div className="h-8 w-px bg-blue-800 mx-1 hidden sm:block"></div>
            <div className="text-right hidden sm:block">
              <div className="text-sm font-bold flex items-center gap-2 justify-end">
                <UserCircle size={16}/> {currentUser.name}
              </div>
              <div className="text-xs text-blue-300 uppercase bg-[#002a42] px-2 py-0.5 rounded inline-block mt-0.5">
                {currentUser.role === 'admin' ? 'Quản trị viên' : currentUser.role === 'subadmin' ? 'Phó ban quản lý' : 'Chuyên viên'}
              </div>
            </div>
            <div className="h-8 w-px bg-blue-800 mx-1"></div>
            <button 
              onClick={handleLogout}
              className="flex items-center gap-1 text-red-200 hover:text-white hover:bg-red-900/50 px-3 py-1.5 rounded transition text-xs font-medium border border-transparent hover:border-red-400"
              title="Đăng xuất"
            >
               <LogOut size={14} /> Đăng xuất
            </button>
          </div>
        </div>
      </header>

      <main className="flex-1 max-w-[1400px] w-full mx-auto p-4 space-y-4">

        {/* Dashboard Cards */}
        <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
          <div className="bg-white p-4 border border-gray-300 shadow-sm flex items-center justify-between rounded-sm relative overflow-hidden group">
            <div className="absolute left-0 top-0 bottom-0 w-1 bg-blue-600"></div>
            <div>
              <p className="text-gray-500 font-semibold uppercase text-xs">Tổng số hồ sơ</p>
              <p className="text-2xl font-bold text-gray-800 mt-1">{stats.total}</p>
            </div>
            <div className="bg-blue-50 p-2 rounded text-blue-600">
              <FileText size={20} />
            </div>
          </div>

          <div className="bg-white p-4 border border-gray-300 shadow-sm flex items-center justify-between rounded-sm relative overflow-hidden">
             <div className="absolute left-0 top-0 bottom-0 w-1 bg-red-600"></div>
            <div>
              <p className="text-gray-500 font-semibold uppercase text-xs">Đang bị ngăn chặn</p>
              <p className="text-2xl font-bold text-red-700 mt-1">{stats.blocked}</p>
            </div>
            <div className="bg-red-50 p-2 rounded text-red-600">
              <Lock size={20} />
            </div>
          </div>

          <div className="bg-white p-4 border border-gray-300 shadow-sm flex items-center justify-between rounded-sm relative overflow-hidden">
             <div className="absolute left-0 top-0 bottom-0 w-1 bg-green-600"></div>
            <div>
              <p className="text-gray-500 font-semibold uppercase text-xs">Đã giải ngăn chặn</p>
              <p className="text-2xl font-bold text-green-700 mt-1">{stats.unblocked}</p>
            </div>
            <div className="bg-green-50 p-2 rounded text-green-600">
              <Unlock size={20} />
            </div>
          </div>
        </div>

        {/* Toolbar & Filter */}
        <div className="bg-white border border-gray-300 shadow-sm rounded-sm">
           <div className="flex flex-col md:flex-row justify-between items-center gap-3 p-3">
              <div className="flex items-center gap-2 flex-1 w-full md:w-auto">
                <div className="relative flex-1 md:max-w-md">
                  <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none">
                    <Search className="h-4 w-4 text-gray-500" />
                  </div>
                  <input
                    type="text"
                    className="block w-full pl-9 pr-3 py-2 border border-gray-400 rounded-sm leading-5 bg-white placeholder-gray-500 focus:outline-none focus:ring-1 focus:ring-blue-600 focus:border-blue-600 sm:text-sm"
                    placeholder="Nhập tên, số tờ, số thửa, số GCN..."
                    value={searchTerm}
                    onChange={(e) => setSearchTerm(e.target.value)}
                  />
                </div>
                <button 
                  onClick={() => setShowFilters(!showFilters)}
                  className={`flex items-center gap-2 px-3 py-2 rounded-sm border transition-colors text-sm font-medium ${showFilters ? 'bg-blue-50 border-blue-300 text-blue-700' : 'bg-gray-50 border-gray-300 text-gray-600 hover:bg-gray-100'}`}
                  title="Bộ lọc nâng cao"
                >
                  <Filter size={16} /> <span className="hidden sm:inline">Bộ lọc</span>
                </button>
              </div>

              {canAdd && (
                <button
                  onClick={() => { setEditingRecord(undefined); setIsFormOpen(true); }}
                  className="flex items-center gap-2 bg-[#006699] text-white px-4 py-2 rounded-sm hover:bg-[#004d73] transition text-sm font-medium shadow-sm uppercase whitespace-nowrap"
                >
                  <Plus size={16} />
                  Thêm Mới
                </button>
              )}
           </div>

           {/* Advanced Filter Panel */}
           {showFilters && (
             <div className="p-4 border-t border-gray-200 bg-gray-50 animate-in slide-in-from-top-2 duration-200">
               <div className="flex justify-between items-center mb-3">
                  <h3 className="text-xs font-bold text-gray-500 uppercase tracking-wider">Tiêu chí lọc nâng cao</h3>
                  <button onClick={resetFilters} className="text-xs text-red-600 hover:text-red-800 flex items-center gap-1 hover:underline">
                      <XCircle size={14} /> Xóa điều kiện lọc
                  </button>
               </div>
               <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-4">
                  <div>
                    <label className="block text-xs font-semibold text-gray-600 mb-1">Trạng thái hồ sơ</label>
                    <select 
                      value={filterStatus}
                      onChange={(e) => setFilterStatus(e.target.value as any)}
                      className="w-full border border-gray-300 rounded-sm px-3 py-2 text-sm focus:border-blue-600 outline-none bg-white"
                    >
                      <option value="all">Tất cả trạng thái</option>
                      <option value="blocked">Đang ngăn chặn</option>
                      <option value="unblocked">Đã giải ngăn chặn</option>
                    </select>
                  </div>
                  <div>
                    <label className="block text-xs font-semibold text-gray-600 mb-1">Cơ quan ban hành</label>
                    <select
                      value={filterAgency}
                      onChange={(e) => setFilterAgency(e.target.value)}
                      className="w-full border border-gray-300 rounded-sm px-3 py-2 text-sm focus:border-blue-600 outline-none bg-white"
                    >
                      <option value="">Tất cả cơ quan</option>
                      {uniqueAgencies.map(agency => (
                        <option key={agency} value={agency}>{agency}</option>
                      ))}
                    </select>
                  </div>
                  <div>
                    <label className="block text-xs font-semibold text-gray-600 mb-1">Xã/Phường (Cũ)</label>
                    <input 
                      type="text" 
                      value={filterOldCommune}
                      onChange={(e) => setFilterOldCommune(e.target.value)}
                      placeholder="Nhập tên xã cũ..."
                      className="w-full border border-gray-300 rounded-sm px-3 py-2 text-sm focus:border-blue-600 outline-none placeholder-gray-400"
                    />
                  </div>
                  <div>
                    <label className="block text-xs font-semibold text-gray-600 mb-1">Xã/Phường (Mới)</label>
                    <input 
                      type="text" 
                      value={filterNewCommune}
                      onChange={(e) => setFilterNewCommune(e.target.value)}
                      placeholder="Nhập tên xã mới..."
                      className="w-full border border-gray-300 rounded-sm px-3 py-2 text-sm focus:border-blue-600 outline-none placeholder-gray-400"
                    />
                  </div>

                  {/* Row 2 */}
                  <div>
                    <label className="block text-xs font-semibold text-gray-600 mb-1">Từ ngày (VB Ngăn chặn)</label>
                    <input 
                      type="date" 
                      value={dateRange.start}
                      onChange={(e) => setDateRange(prev => ({ ...prev, start: e.target.value }))}
                      className="w-full border border-gray-300 rounded-sm px-3 py-2 text-sm focus:border-blue-600 outline-none"
                    />
                  </div>
                  <div>
                    <label className="block text-xs font-semibold text-gray-600 mb-1">Đến ngày</label>
                    <input 
                      type="date" 
                      value={dateRange.end}
                      onChange={(e) => setDateRange(prev => ({ ...prev, end: e.target.value }))}
                      className="w-full border border-gray-300 rounded-sm px-3 py-2 text-sm focus:border-blue-600 outline-none"
                    />
                  </div>
               </div>
             </div>
           )}
        </div>

        {/* Data Table */}
        <div className="bg-white border border-gray-300 shadow-sm overflow-hidden rounded-sm">
          <div className="overflow-x-auto">
            <table className="min-w-full border-collapse">
              <thead>
                <tr className="bg-gray-100 border-b-2 border-blue-800 text-gray-700 text-xs uppercase font-bold tracking-wider">
                  <th className="px-3 py-3 border-r border-gray-300 w-10 text-center">STT</th>
                  <th className="px-3 py-3 border-r border-gray-300 text-left w-64">Chủ Sử Dụng & GCN</th>
                  <th className="px-3 py-3 border-r border-gray-300 text-left w-56">Đặc Điểm & Vị Trí</th>
                  <th className="px-3 py-3 border-r border-gray-300 text-left">Nội Dung Ngăn Chặn</th>
                  <th className="px-3 py-3 border-r border-gray-300 text-center w-32">Trạng Thái</th>
                  {(canEdit || canDelete) && (
                    <th className="px-3 py-3 text-center w-24">Tác Vụ</th>
                  )}
                </tr>
              </thead>
              <tbody className="bg-white divide-y divide-gray-200 text-sm text-gray-800">
                {filteredRecords.length > 0 ? (
                  filteredRecords.map((record, index) => (
                    <tr 
                      key={record.id} 
                      className={`hover:bg-blue-50 transition-colors ${!record.isUnblocked ? 'bg-red-50/30' : ''}`}
                    >
                      <td className="px-3 py-2 border-r border-gray-300 text-center font-medium text-gray-500">
                        {index + 1}
                      </td>
                      <td className="px-3 py-2 border-r border-gray-300 align-top">
                        <div className="font-bold text-[#003b5c] uppercase mb-1">
                          {record.owners.join(', ')}
                        </div>
                        <div className="text-xs space-y-0.5 text-gray-600">
                             <div className="flex justify-between"><span>Số PH:</span> <span className="font-medium text-black">{record.issueNumber}</span></div>
                             <div className="flex justify-between"><span>Số vào sổ:</span> <span className="font-medium text-black">{record.certNumber}</span></div>
                             <div className="flex justify-between"><span>Ngày cấp:</span> <span>{record.issueDate}</span></div>
                        </div>
                      </td>
                      <td className="px-3 py-2 border-r border-gray-300 align-top">
                        {/* Thông tin kỹ thuật */}
                        <div className="grid grid-cols-2 gap-2 text-xs mb-2 pb-2 border-b border-gray-200">
                           <div className="bg-gray-50 border border-gray-200 rounded p-1 text-center">
                              <span className="block text-[10px] text-gray-500 uppercase">Tờ số</span>
                              <b className="text-black text-sm">{record.mapSheetNumber}</b>
                           </div>
                           <div className="bg-gray-50 border border-gray-200 rounded p-1 text-center">
                              <span className="block text-[10px] text-gray-500 uppercase">Thửa số</span>
                              <b className="text-black text-sm">{record.plotNumber}</b>
                           </div>
                           <div className="col-span-2 text-center text-xs">
                              Diện tích: <b className="text-[#003b5c]">{record.area}</b> m²
                           </div>
                        </div>

                        {/* Thông tin địa chính phân tách rõ ràng */}
                        <div className="text-xs space-y-1">
                             <div className="flex items-start gap-1 font-semibold text-gray-800">
                                <MapPin size={12} className="mt-0.5 text-red-500 flex-shrink-0"/>
                                <span>{record.hamlet}</span>
                             </div>

                             <div className="flex flex-col gap-1 mt-1">
                                <div className="flex items-center justify-between bg-gray-100 px-2 py-1 rounded border border-gray-200">
                                    <span className="text-[9px] font-bold text-gray-500 uppercase w-8">CŨ</span>
                                    <span className="text-gray-600 italic text-right flex-1">{record.oldCommune}</span>
                                </div>

                                <div className="flex justify-center text-gray-400 -my-1.5 z-10">
                                   <ArrowRight size={10} className="rotate-90"/>
                                </div>

                                <div className="flex items-center justify-between bg-blue-50 px-2 py-1 rounded border border-blue-100">
                                    <span className="text-[9px] font-bold text-blue-600 uppercase w-8">MỚI</span>
                                    <span className="text-blue-800 font-bold text-right flex-1">{record.newCommune}</span>
                                </div>
                             </div>
                        </div>
                      </td>
                      <td className="px-3 py-2 border-r border-gray-300 align-top">
                         {/* Hiển thị danh sách văn bản ngăn chặn */}
                         <div className="space-y-2 mb-2">
                             {record.blockingDocuments.map((doc, docIndex) => (
                                 <div key={docIndex} className="bg-red-50 border border-red-100 p-1.5 rounded-sm">
                                     <div className="text-red-700 font-semibold text-xs uppercase flex items-center gap-1">
                                        <FileText size={12}/> VB: {doc.docNumber}
                                     </div>
                                     <div className="text-xs mt-0.5 pl-4 text-gray-600 flex flex-wrap gap-x-2">
                                        <span className="flex items-center gap-1"><Calendar size={10}/> {doc.date}</span>
                                        <span className="flex items-center gap-1 font-medium"><Building2 size={10}/> {doc.agency}</span>
                                     </div>
                                 </div>
                             ))}
                         </div>

                         {record.isUnblocked && (
                           <div className="mt-2 pt-2 border-t border-dashed border-gray-300">
                               <div className="text-green-700 font-semibold text-xs uppercase flex items-center gap-1">
                                  <Unlock size={12}/> VB Hủy bỏ: {record.unblockDoc}
                                </div>
                           </div>
                         )}

                         {record.notes && (
                            <div className="mt-2 text-xs bg-yellow-50 text-yellow-800 p-1.5 border border-yellow-200 rounded-sm italic">
                                Lưu ý: {record.notes}
                            </div>
                         )}
                      </td>
                      <td className="px-3 py-2 border-r border-gray-300 text-center align-middle">
                        {record.isUnblocked ? (
                            <span className="inline-flex items-center px-2.5 py-1 rounded border border-green-200 bg-green-100 text-green-800 text-xs font-bold uppercase tracking-wide">
                                Đã giải ngăn chặn
                            </span>
                        ) : (
                            <span className="inline-flex items-center px-2.5 py-1 rounded border border-red-200 bg-red-100 text-red-800 text-xs font-bold uppercase tracking-wide animate-pulse">
                                Ngăn chặn
                            </span>
                        )}
                      </td>
                      {(canEdit || canDelete) && (
                        <td className="px-3 py-2 text-center align-middle">
                            <div className="flex justify-center gap-1">
                                {canEdit && (
                                    <button 
                                        onClick={() => startEdit(record)}
                                        className="text-blue-600 hover:text-white hover:bg-blue-600 p-1.5 rounded transition"
                                        title="Chỉnh sửa hồ sơ"
                                    >
                                        <Edit size={16} />
                                    </button>
                                )}
                                {canDelete && (
                                    <button 
                                        onClick={() => handleDeleteRecord(record.id)}
                                        className="text-gray-500 hover:text-white hover:bg-red-600 p-1.5 rounded transition"
                                        title="Xóa hồ sơ"
                                    >
                                        <Trash2 size={16} />
                                    </button>
                                )}
                            </div>
                        </td>
                      )}
                    </tr>
                  ))
                ) : (
                  <tr>
                    <td colSpan={canEdit || canDelete ? 6 : 5} className="px-6 py-10 text-center text-gray-500 italic">
                      Không tìm thấy hồ sơ nào phù hợp với các tiêu chí tìm kiếm.
                    </td>
                  </tr>
                )}
              </tbody>
            </table>
          </div>
          <div className="p-2 border-t border-gray-300 text-xs text-gray-600 bg-gray-50 flex justify-between items-center">
             <span>Tổng số: <b>{filteredRecords.length}</b> bản ghi</span>
             <span className="italic opacity-70">Hệ thống quản lý đất đai v1.0</span>
          </div>
        </div>
      </main>

      {/* Modal Form */}
      {isFormOpen && (
        <RecordForm
          initialData={editingRecord}
          onSubmit={editingRecord ? handleUpdateRecord : handleAddRecord}
          onCancel={() => { setIsFormOpen(false); setEditingRecord(undefined); }}
        />
      )}
    </div>
  );
}

export default App;

import React, { useState, useEffect } from 'react';
import { LandRecord, LandRecordFormData, BlockingDocument } from '../types';
import { Plus, Trash2, X, Save, AlertCircle, FileText } from 'lucide-react';

interface RecordFormProps {
  initialData?: LandRecord;
  onSubmit: (data: LandRecordFormData) => void;
  onCancel: () => void;
}

const RecordForm: React.FC<RecordFormProps> = ({ initialData, onSubmit, onCancel }) => {
  const [formData, setFormData] = useState<LandRecordFormData>({
    owners: [''],
    issueNumber: '',
    certNumber: '',
    issueDate: new Date().toISOString().split('T')[0],
    area: 0,
    plotNumber: '',
    mapSheetNumber: '',
    hamlet: '',
    oldCommune: '',
    newCommune: '',
    blockingDocuments: [{ docNumber: '', date: new Date().toISOString().split('T')[0], agency: '' }],
    unblockDoc: '',
    notes: '',
    isUnblocked: false,
  });

  useEffect(() => {
    if (initialData) {
      setFormData(initialData);
    }
  }, [initialData]);

  const handleChange = (e: React.ChangeEvent<HTMLInputElement | HTMLTextAreaElement | HTMLSelectElement>) => {
    const { name, value, type } = e.target;
    if (type === 'checkbox') {
      const checked = (e.target as HTMLInputElement).checked;
      setFormData(prev => ({ ...prev, [name]: checked }));
    } else {
      setFormData(prev => ({ ...prev, [name]: value }));
    }
  };

  // --- Owners Logic ---
  const handleOwnerChange = (index: number, value: string) => {
    const newOwners = [...formData.owners];
    newOwners[index] = value;
    setFormData(prev => ({ ...prev, owners: newOwners }));
  };

  const addOwnerField = () => {
    setFormData(prev => ({ ...prev, owners: [...prev.owners, ''] }));
  };

  const removeOwnerField = (index: number) => {
    if (formData.owners.length > 1) {
      const newOwners = formData.owners.filter((_, i) => i !== index);
      setFormData(prev => ({ ...prev, owners: newOwners }));
    }
  };

  // --- Blocking Documents Logic ---
  const handleBlockingDocChange = (index: number, field: keyof BlockingDocument, value: string) => {
    const newDocs = [...formData.blockingDocuments];
    newDocs[index] = { ...newDocs[index], [field]: value };
    setFormData(prev => ({ ...prev, blockingDocuments: newDocs }));
  };

  const addBlockingDoc = () => {
    setFormData(prev => ({
      ...prev,
      blockingDocuments: [...prev.blockingDocuments, { docNumber: '', date: new Date().toISOString().split('T')[0], agency: '' }]
    }));
  };

  const removeBlockingDoc = (index: number) => {
    if (formData.blockingDocuments.length > 1) {
      const newDocs = formData.blockingDocuments.filter((_, i) => i !== index);
      setFormData(prev => ({ ...prev, blockingDocuments: newDocs }));
    }
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    onSubmit(formData);
  };

  return (
    <div className="fixed inset-0 bg-black/60 flex justify-center items-center z-50 p-4 font-sans">
      <div className="bg-white shadow-2xl w-full max-w-4xl max-h-[95vh] flex flex-col rounded-sm overflow-hidden">
        {/* Header Modal */}
        <div className="flex justify-between items-center px-6 py-4 bg-[#003b5c] text-white border-b border-blue-800 shrink-0">
          <div>
            <h2 className="text-lg font-bold uppercase tracking-wide">
              {initialData ? 'CẬP NHẬT THÔNG TIN HỒ SƠ' : 'NHẬP LIỆU HỒ SƠ NGĂN CHẶN MỚI'}
            </h2>
            <p className="text-xs text-blue-200 opacity-80">Vui lòng nhập đầy đủ thông tin chính xác theo văn bản</p>
          </div>
          <button onClick={onCancel} className="text-white hover:text-red-300 transition-colors">
            <X size={24} />
          </button>
        </div>

        {/* Form Body */}
        <div className="flex-1 overflow-y-auto bg-gray-50 p-6">
          <form id="recordForm" onSubmit={handleSubmit} className="space-y-6">

            {/* Group 1: Thông tin chủ & GCN */}
            <div className="bg-white border border-gray-300 shadow-sm rounded-sm">
                <div className="bg-gray-100 px-4 py-2 border-b border-gray-300 font-bold text-[#003b5c] text-sm uppercase flex items-center gap-2">
                    <span className="bg-[#003b5c] text-white w-6 h-6 flex items-center justify-center rounded-full text-xs">1</span>
                    Thông tin Chủ Sử Dụng & Giấy Chứng Nhận
                </div>
                <div className="p-4 grid grid-cols-1 md:grid-cols-2 gap-4">
                     <div className="md:col-span-2 space-y-2">
                        <label className="block text-xs font-bold text-gray-700 uppercase">Tên chủ sử dụng (Viết hoa)</label>
                        {formData.owners.map((owner, index) => (
                          <div key={index} className="flex gap-2">
                            <input
                              type="text"
                              required
                              value={owner}
                              onChange={(e) => handleOwnerChange(index, e.target.value.toUpperCase())}
                              placeholder="NGUYỄN VĂN A"
                              className="flex-1 border border-gray-300 px-3 py-2 text-sm rounded-sm focus:ring-1 focus:ring-blue-600 focus:border-blue-600 outline-none uppercase"
                            />
                            {formData.owners.length > 1 && (
                              <button
                                type="button"
                                onClick={() => removeOwnerField(index)}
                                className="text-red-500 hover:bg-red-50 px-2 rounded border border-transparent hover:border-red-200"
                              >
                                <Trash2 size={16} />
                              </button>
                            )}
                          </div>
                        ))}
                        <button
                          type="button"
                          onClick={addOwnerField}
                          className="text-xs text-blue-700 hover:underline flex items-center gap-1 font-medium mt-1"
                        >
                          <Plus size={12} /> Thêm đồng sở hữu
                        </button>
                     </div>

                     <div className="grid grid-cols-3 gap-3 md:col-span-2 border-t border-gray-100 pt-3 mt-1">
                        <div>
                            <label className="block text-xs font-semibold text-gray-600 mb-1">Số phát hành (Serial)</label>
                            <input
                                type="text"
                                name="issueNumber"
                                value={formData.issueNumber}
                                onChange={handleChange}
                                className="w-full border border-gray-300 px-3 py-2 text-sm rounded-sm focus:border-blue-600 outline-none"
                            />
                        </div>
                        <div>
                            <label className="block text-xs font-semibold text-gray-600 mb-1">Số vào sổ cấp GCN</label>
                            <input
                                type="text"
                                name="certNumber"
                                value={formData.certNumber}
                                onChange={handleChange}
                                className="w-full border border-gray-300 px-3 py-2 text-sm rounded-sm focus:border-blue-600 outline-none"
                            />
                        </div>
                        <div>
                            <label className="block text-xs font-semibold text-gray-600 mb-1">Ngày cấp</label>
                            <input
                                type="date"
                                name="issueDate"
                                value={formData.issueDate}
                                onChange={handleChange}
                                className="w-full border border-gray-300 px-3 py-2 text-sm rounded-sm focus:border-blue-600 outline-none"
                            />
                        </div>
                     </div>
                </div>
            </div>

            {/* Group 2: Thông tin thửa đất */}
            <div className="bg-white border border-gray-300 shadow-sm rounded-sm">
                <div className="bg-gray-100 px-4 py-2 border-b border-gray-300 font-bold text-[#003b5c] text-sm uppercase flex items-center gap-2">
                    <span className="bg-[#003b5c] text-white w-6 h-6 flex items-center justify-center rounded-full text-xs">2</span>
                    Đặc điểm Thửa Đất
                </div>
                <div className="p-4 grid grid-cols-1 md:grid-cols-3 gap-4">
                     <div>
                        <label className="block text-xs font-semibold text-gray-600 mb-1">Tờ bản đồ số</label>
                        <input
                            type="text"
                            name="mapSheetNumber"
                            value={formData.mapSheetNumber}
                            onChange={handleChange}
                            className="w-full border border-gray-300 px-3 py-2 text-sm rounded-sm focus:border-blue-600 outline-none font-medium"
                        />
                     </div>
                     <div>
                        <label className="block text-xs font-semibold text-gray-600 mb-1">Thửa đất số</label>
                        <input
                            type="text"
                            name="plotNumber"
                            value={formData.plotNumber}
                            onChange={handleChange}
                            className="w-full border border-gray-300 px-3 py-2 text-sm rounded-sm focus:border-blue-600 outline-none font-medium"
                        />
                     </div>
                     <div>
                        <label className="block text-xs font-semibold text-gray-600 mb-1">Diện tích (m²)</label>
                        <input
                            type="number"
                            name="area"
                            value={formData.area}
                            onChange={handleChange}
                            className="w-full border border-gray-300 px-3 py-2 text-sm rounded-sm focus:border-blue-600 outline-none"
                        />
                     </div>

                     <div className="md:col-span-3 grid grid-cols-3 gap-3">
                         <div className="col-span-1">
                            <label className="block text-xs font-semibold text-gray-600 mb-1">Ấp/Khu phố</label>
                            <input
                                type="text"
                                name="hamlet"
                                value={formData.hamlet}
                                onChange={handleChange}
                                className="w-full border border-gray-300 px-3 py-2 text-sm rounded-sm focus:border-blue-600 outline-none"
                            />
                         </div>
                         <div className="col-span-1">
                            <label className="block text-xs font-semibold text-gray-600 mb-1">Xã/Phường (Trước sát nhập)</label>
                            <input
                                type="text"
                                name="oldCommune"
                                value={formData.oldCommune}
                                onChange={handleChange}
                                className="w-full border border-gray-300 px-3 py-2 text-sm rounded-sm focus:border-blue-600 outline-none italic"
                            />
                         </div>
                         <div className="col-span-1">
                            <label className="block text-xs font-semibold text-gray-600 mb-1">Xã/Phường (Hiện tại)</label>
                            <input
                                type="text"
                                name="newCommune"
                                value={formData.newCommune}
                                onChange={handleChange}
                                className="w-full border border-gray-300 px-3 py-2 text-sm rounded-sm focus:border-blue-600 outline-none"
                            />
                         </div>
                     </div>
                </div>
            </div>

            {/* Group 3: Tình trạng ngăn chặn (Đã cập nhật để hỗ trợ nhiều văn bản) */}
            <div className="bg-white border border-gray-300 shadow-sm rounded-sm">
                <div className="bg-red-50 px-4 py-2 border-b border-red-200 font-bold text-red-800 text-sm uppercase flex justify-between items-center">
                    <div className="flex items-center gap-2">
                         <span className="bg-red-700 text-white w-6 h-6 flex items-center justify-center rounded-full text-xs">3</span>
                         Nội dung Ngăn Chặn
                    </div>
                    <button
                        type="button"
                        onClick={addBlockingDoc}
                        className="text-xs bg-red-100 hover:bg-red-200 text-red-800 px-2 py-1 rounded border border-red-200 flex items-center gap-1 transition-colors"
                    >
                        <Plus size={12} /> Thêm văn bản
                    </button>
                </div>

                <div className="p-4 space-y-4">
                    {formData.blockingDocuments.map((doc, index) => (
                        <div key={index} className="grid grid-cols-1 md:grid-cols-12 gap-3 items-start border-b border-gray-100 pb-4 last:border-0 last:pb-0 relative">
                             {/* Indicator Line */}
                             <div className="hidden md:block absolute left-[-16px] top-2 bottom-0 w-1 bg-red-100 rounded-r"></div>

                             <div className="md:col-span-5">
                                <label className="block text-xs font-bold text-red-700 mb-1 uppercase">
                                    Số văn bản ngăn chặn {formData.blockingDocuments.length > 1 ? `#${index + 1}` : ''} (*)
                                </label>
                                <input
                                    type="text"
                                    required
                                    value={doc.docNumber}
                                    onChange={(e) => handleBlockingDocChange(index, 'docNumber', e.target.value)}
                                    className="w-full border border-red-300 bg-red-50 px-3 py-2 text-sm rounded-sm focus:border-red-600 outline-none font-semibold text-red-900"
                                    placeholder="Nhập số CV/QĐ..."
                                />
                             </div>
                             <div className="md:col-span-3">
                                <label className="block text-xs font-semibold text-gray-600 mb-1">Ngày văn bản</label>
                                <input
                                    type="date"
                                    value={doc.date}
                                    onChange={(e) => handleBlockingDocChange(index, 'date', e.target.value)}
                                    className="w-full border border-gray-300 px-3 py-2 text-sm rounded-sm focus:border-blue-600 outline-none"
                                />
                             </div>
                             <div className="md:col-span-3">
                                <label className="block text-xs font-semibold text-gray-600 mb-1">Cơ quan ban hành</label>
                                <input
                                    type="text"
                                    value={doc.agency}
                                    onChange={(e) => handleBlockingDocChange(index, 'agency', e.target.value)}
                                    className="w-full border border-gray-300 px-3 py-2 text-sm rounded-sm focus:border-blue-600 outline-none"
                                    placeholder="Tòa án/THADS..."
                                />
                             </div>

                             <div className="md:col-span-1 flex items-end justify-center pt-6">
                                {formData.blockingDocuments.length > 1 && (
                                    <button
                                        type="button"
                                        onClick={() => removeBlockingDoc(index)}
                                        className="text-red-400 hover:text-red-600 hover:bg-red-50 p-2 rounded transition"
                                        title="Xóa văn bản này"
                                    >
                                        <Trash2 size={16} />
                                    </button>
                                )}
                             </div>
                        </div>
                    ))}

                    <div className="pt-2 border-t border-gray-100">
                        <label className="block text-xs font-semibold text-gray-600 mb-1">Ghi chú thêm</label>
                        <textarea
                            name="notes"
                            rows={2}
                            value={formData.notes}
                            onChange={handleChange}
                            className="w-full border border-gray-300 px-3 py-2 text-sm rounded-sm focus:border-blue-600 outline-none"
                        />
                    </div>
                </div>
            </div>

            {/* Group 4: Giải tỏa */}
            <div className={`border shadow-sm rounded-sm transition-colors ${formData.isUnblocked ? 'bg-green-50 border-green-300' : 'bg-gray-50 border-gray-200'}`}>
                <div className="px-4 py-3 flex items-center justify-between">
                    <div className="flex items-center gap-3">
                        <input
                            type="checkbox"
                            id="isUnblocked"
                            name="isUnblocked"
                            checked={formData.isUnblocked}
                            onChange={handleChange}
                            className="h-5 w-5 text-green-600 focus:ring-green-500 border-gray-300 rounded cursor-pointer"
                        />
                        <label htmlFor="isUnblocked" className={`font-bold uppercase text-sm cursor-pointer select-none ${formData.isUnblocked ? 'text-green-800' : 'text-gray-500'}`}>
                            Đã có văn bản giải ngăn chặn / Hủy ngăn chặn
                        </label>
                    </div>
                </div>

                {formData.isUnblocked && (
                    <div className="p-4 border-t border-green-200 animate-in fade-in slide-in-from-top-2 duration-200">
                        <label className="block text-xs font-bold text-green-800 mb-1 uppercase">Số văn bản hủy bỏ / Giải tỏa</label>
                        <input
                            type="text"
                            name="unblockDoc"
                            value={formData.unblockDoc}
                            onChange={handleChange}
                            className="w-full border border-green-300 px-3 py-2 text-sm rounded-sm focus:border-green-600 outline-none font-medium"
                            placeholder="Nhập số văn bản..."
                            required={formData.isUnblocked}
                        />
                    </div>
                )}
            </div>

          </form>
        </div>

        {/* Footer Actions */}
        <div className="p-4 border-t border-gray-200 bg-gray-50 flex justify-end gap-3 shrink-0">
          <button
            type="button"
            onClick={onCancel}
            className="px-5 py-2 bg-white text-gray-700 border border-gray-300 rounded-sm hover:bg-gray-100 transition-colors text-sm font-medium uppercase"
          >
            Đóng
          </button>
          <button
            type="submit"
            form="recordForm"
            className="px-5 py-2 bg-[#00507d] text-white rounded-sm hover:bg-[#003b5c] transition-colors text-sm font-bold uppercase shadow-sm flex items-center gap-2"
          >
            <Save size={16} /> Lưu Dữ Liệu
          </button>
        </div>
      </div>
    </div>
  );
};

export default RecordForm;

// Định nghĩa chi tiết văn bản ngăn chặn
export interface BlockingDocument {
  docNumber: string; // Số hiệu văn bản
  date: string; // Ngày ban hành
  agency: string; // Cơ quan ban hành
  note: string; // Ghi chú riêng cho văn bản này
}

// Định nghĩa cấu trúc dữ liệu cho một hồ sơ đất đai
export interface LandRecord {
  id: string;
  owners: string[]; // Mảng chứa tên các chủ sử dụng
  issueNumber: string; // Số phát hành (Serial sổ đỏ)
  certNumber: string; // Số vào sổ cấp giấy
  issueDate: string; // Ngày cấp
  area: number; // Diện tích (m2)
  plotNumber: string; // Số thửa
  mapSheetNumber: string; // Số tờ
  hamlet: string; // Ấp/Khu phố
  oldCommune: string; // Xã/Phường trước sát nhập
  newCommune: string; // Xã/Phường sau sát nhập

  // Thay đổi: Hỗ trợ nhiều văn bản ngăn chặn
  blockingDocuments: BlockingDocument[];

  unblockDoc: string; // Văn bản hủy ngăn chặn (nếu có)
  notes: string; // Ghi chú chung cho cả hồ sơ
  isUnblocked: boolean; // Trạng thái: true = đã giải tỏa, false = đang ngăn chặn
}

// Kiểu dữ liệu cho Form (không có ID vì ID tự sinh)
export type LandRecordFormData = Omit<LandRecord, 'id'>;

// Định nghĩa Role và User
export type UserRole = 'admin' | 'subadmin' | 'user';

export interface User {
  username: string;
  name: string;
  role: UserRole;
}

import React, { useState, useMemo } from 'react';
import { LandRecord, LandRecordFormData, User } from './types';
import RecordForm from './components/RecordForm';
import LoginForm from './components/LoginForm';
import { Search, Plus, Edit, Trash2, FileText, Lock, Unlock, MapPin, Printer, ArrowRight, Filter, XCircle, LogOut, UserCircle, Calendar, Building2, Info } from 'lucide-react';

// Dữ liệu mẫu ban đầu (Đã cập nhật cấu trúc mảng và thêm note)
const MOCK_DATA: LandRecord[] = [
  {
    id: '1',
    owners: ['NGUYỄN VĂN A', 'TRẦN THỊ B'],
    issueNumber: 'AB 123456',
    certNumber: 'CH001',
    issueDate: '2020-01-15',
    area: 150.5,
    plotNumber: '12',
    mapSheetNumber: '5',
    hamlet: 'Khu phố 1',
    oldCommune: 'Phường X cũ',
    newCommune: 'Phường Y mới',
    blockingDocuments: [
        { docNumber: 'CV-100/TA', date: '2023-05-20', agency: 'Tòa án ND Huyện', note: 'Tranh chấp quyền thừa kế' }
    ],
    unblockDoc: '',
    notes: 'Hồ sơ đang thụ lý',
    isUnblocked: false,
  },
  {
    id: '2',
    owners: ['LÊ VĂN C'],
    issueNumber: 'CD 987654',
    certNumber: 'CH002',
    issueDate: '2019-11-30',
    area: 300,
    plotNumber: '45',
    mapSheetNumber: '10',
    hamlet: 'Ấp 2',
    oldCommune: 'Xã Z',
    newCommune: 'Xã Z',
    blockingDocuments: [
        { docNumber: 'TB-ThiHanhAn', date: '2022-02-15', agency: 'Chi cục THADS', note: 'Phong tỏa tài sản để THA' },
        { docNumber: 'CV-BoSung-01', date: '2022-03-01', agency: 'Chi cục THADS', note: 'Bổ sung thông tin thửa đất' }
    ],
    unblockDoc: 'QD-GiaiToa-01',
    notes: '',
    isUnblocked: true,
  },
];

function App() {
  const [currentUser, setCurrentUser] = useState<User | null>(null);
  const [records, setRecords] = useState<LandRecord[]>(MOCK_DATA);
  const [isFormOpen, setIsFormOpen] = useState(false);
  const [editingRecord, setEditingRecord] = useState<LandRecord | undefined>(undefined);

  // State tìm kiếm và lọc
  const [searchTerm, setSearchTerm] = useState('');
  const [showFilters, setShowFilters] = useState(false);
  const [filterStatus, setFilterStatus] = useState<'all' | 'blocked' | 'unblocked'>('all');
  const [filterAgency, setFilterAgency] = useState('');
  const [dateRange, setDateRange] = useState<{ start: string; end: string }>({ start: '', end: '' });

  // State lọc xã phường mới
  const [filterOldCommune, setFilterOldCommune] = useState('');
  const [filterNewCommune, setFilterNewCommune] = useState('');

  // Danh sách cơ quan duy nhất (Lấy từ mảng blockingDocuments)
  const uniqueAgencies = useMemo(() => {
    const agencies = records.flatMap(r => r.blockingDocuments.map(doc => doc.agency));
    return Array.from(new Set(agencies.filter(Boolean))).sort();
  }, [records]);

  // Lọc hồ sơ tổng hợp
  const filteredRecords = useMemo(() => {
    return records.filter(record => {
      // 1. Tìm kiếm từ khóa chung
      const searchLower = searchTerm.toLowerCase();
      const ownersString = record.owners.join(' ').toLowerCase();
      // Kiểm tra xem có văn bản nào khớp số hiệu hoặc ghi chú không
      const hasMatchingDoc = record.blockingDocuments.some(doc => 
          doc.docNumber.toLowerCase().includes(searchLower) || 
          doc.note.toLowerCase().includes(searchLower)
      );

      const matchesSearch = (
        ownersString.includes(searchLower) ||
        record.plotNumber.includes(searchLower) ||
        record.mapSheetNumber.includes(searchLower) ||
        record.issueNumber.toLowerCase().includes(searchLower) ||
        record.certNumber.toLowerCase().includes(searchLower) ||
        hasMatchingDoc
      );

      // 2. Lọc theo trạng thái
      const matchesStatus =
        filterStatus === 'all'
          ? true
          : filterStatus === 'blocked'
          ? !record.isUnblocked
          : record.isUnblocked;

      // 3. Lọc theo cơ quan (Kiểm tra trong mảng văn bản)
      const matchesAgency = filterAgency === '' || record.blockingDocuments.some(doc => doc.agency === filterAgency);

      // 4. Lọc theo khoảng thời gian (Kiểm tra bất kỳ văn bản nào nằm trong khoảng)
      let matchesDate = true;
      if (dateRange.start || dateRange.end) {
          const hasDateInRange = record.blockingDocuments.some(doc => {
              if (dateRange.start && doc.date < dateRange.start) return false;
              if (dateRange.end && doc.date > dateRange.end) return false;
              return true;
          });
          if (!hasDateInRange) matchesDate = false;
      }

      // 5. Lọc theo Xã/Phường
      const matchesOldCommune = record.oldCommune.toLowerCase().includes(filterOldCommune.toLowerCase());
      const matchesNewCommune = record.newCommune.toLowerCase().includes(filterNewCommune.toLowerCase());

      return matchesSearch && matchesStatus && matchesAgency && matchesDate && matchesOldCommune && matchesNewCommune;
    });
  }, [records, searchTerm, filterStatus, filterAgency, dateRange, filterOldCommune, filterNewCommune]);

  // Thống kê
  const stats = useMemo(() => {
    const total = records.length;
    const blocked = records.filter(r => !r.isUnblocked).length;
    const unblocked = total - blocked;
    return { total, blocked, unblocked };
  }, [records]);

  // --- Handlers ---
  const handleLogout = () => setCurrentUser(null);

  const handleAddRecord = (data: LandRecordFormData) => {
    const newRecord: LandRecord = { ...data, id: Date.now().toString() };
    setRecords(prev => [newRecord, ...prev]);
    setIsFormOpen(false);
  };

  const handleUpdateRecord = (data: LandRecordFormData) => {
    if (!editingRecord) return;
    setRecords(prev => prev.map(r => r.id === editingRecord.id ? { ...data, id: editingRecord.id } : r));
    setEditingRecord(undefined);
    setIsFormOpen(false);
  };

  const handleDeleteRecord = (id: string) => {
    if (window.confirm('Xác nhận xóa hồ sơ này khỏi hệ thống? Hành động này không thể hoàn tác.')) {
      setRecords(prev => prev.filter(r => r.id !== id));
    }
  };

  const startEdit = (record: LandRecord) => {
    setEditingRecord(record);
    setIsFormOpen(true);
  };

  const resetFilters = () => {
    if (window.confirm('Bạn có chắc chắn muốn xóa toàn bộ điều kiện lọc và quay về danh sách mặc định?')) {
        setFilterStatus('all');
        setFilterAgency('');
        setDateRange({ start: '', end: '' });
        setSearchTerm('');
        setFilterOldCommune('');
        setFilterNewCommune('');
    }
  };

  const handleExportCSV = () => {
    if (filteredRecords.length === 0) {
      alert('Không có dữ liệu để xuất.');
      return;
    }

    // Hàm hỗ trợ escape chuỗi CSV (xử lý dấu phẩy, dấu ngoặc kép)
    const escapeCsv = (str: string | number | null | undefined) => {
      if (str === null || str === undefined) return '""';
      const stringValue = String(str);
      const escaped = stringValue.replace(/"/g, '""');
      return `"${escaped}"`;
    };

    const headers = [
      "STT", "Chủ Sử Dụng", "Số Phát Hành", "Số Vào Sổ", "Ngày Cấp",
      "Diện Tích (m2)", "Tờ Số", "Thửa Số", "Địa Chỉ",
      "Xã/Phường Cũ", "Xã/Phường Mới",
      "Chi Tiết VB Ngăn Chặn (Số - Ngày - CQ - Nội dung)", 
      "Văn Bản Giải Ngăn Chặn", "Trạng Thái", "Ghi Chú Chung"
    ];

    const rows = filteredRecords.map((record, index) => {
       // Gộp danh sách văn bản thành 1 chuỗi
       const docString = record.blockingDocuments.map(d => {
           const notePart = d.note ? `[${d.note}]` : '';
           return `${d.docNumber} (${d.date}) - ${d.agency} ${notePart}`;
       }).join('; ');

       return [
        index + 1,
        record.owners.join(', '),
        record.issueNumber,
        record.certNumber,
        record.issueDate,
        record.area,
        record.mapSheetNumber,
        record.plotNumber,
        record.hamlet,
        record.oldCommune,
        record.newCommune,
        docString,
        record.unblockDoc,
        record.isUnblocked ? 'Đã giải ngăn chặn' : 'Đang ngăn chặn',
        record.notes
      ].map(escapeCsv).join(',');
    });

    const csvContent = [headers.join(','), ...rows].join('\n');

    // Thêm BOM (\uFEFF) để Excel nhận diện đúng tiếng Việt (UTF-8)
    const blob = new Blob(['\uFEFF' + csvContent], { type: 'text/csv;charset=utf-8;' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    link.download = `Bao_cao_ngan_chan_${new Date().toISOString().split('T')[0]}.csv`;
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  // --- Permission Checks ---
  const canAdd = currentUser?.role === 'admin' || currentUser?.role === 'subadmin';
  const canEdit = currentUser?.role === 'admin' || currentUser?.role === 'subadmin';
  const canDelete = currentUser?.role === 'admin';

  // Nếu chưa đăng nhập, hiển thị form login
  if (!currentUser) {
    return <LoginForm onLogin={setCurrentUser} />;
  }

  return (
    <div className="min-h-screen bg-gray-100 flex flex-col font-sans text-sm">
      {/* Administrative Header */}
      <header className="bg-[#003b5c] text-white shadow-md">
        <div className="max-w-[1400px] mx-auto px-4 py-3 flex justify-between items-center">
          <div className="flex items-center gap-3">
            <div className="bg-white p-2 rounded-full shadow-inner">
               <FileText className="text-[#003b5c]" size={24} />
            </div>
            <div>
              <h1 className="text-lg font-bold uppercase tracking-wide">Hệ Thống Quản Lý Ngăn Chặn Đất Đai</h1>
              <p className="text-blue-200 text-xs">Sổ theo dõi ngăn chặn & biến động</p>
            </div>
          </div>

          {/* User Info & Logout */}
          <div className="flex items-center gap-4">
            <button 
                onClick={handleExportCSV}
                className="flex items-center gap-2 bg-[#00507d] hover:bg-[#006699] px-3 py-1.5 rounded text-xs font-medium transition border border-blue-400"
                title="Xuất dữ liệu hiện tại ra file CSV"
            >
                <Printer size={14} /> Xuất Báo Cáo
            </button>
            <div className="h-8 w-px bg-blue-800 mx-1 hidden sm:block"></div>
            <div className="text-right hidden sm:block">
              <div className="text-sm font-bold flex items-center gap-2 justify-end">
                <UserCircle size={16}/> {currentUser.name}
              </div>
              <div className="text-xs text-blue-300 uppercase bg-[#002a42] px-2 py-0.5 rounded inline-block mt-0.5">
                {currentUser.role === 'admin' ? 'Quản trị viên' : currentUser.role === 'subadmin' ? 'Phó ban quản lý' : 'Chuyên viên'}
              </div>
            </div>
            <div className="h-8 w-px bg-blue-800 mx-1"></div>
            <button 
              onClick={handleLogout}
              className="flex items-center gap-1 text-red-200 hover:text-white hover:bg-red-900/50 px-3 py-1.5 rounded transition text-xs font-medium border border-transparent hover:border-red-400"
              title="Đăng xuất"
            >
               <LogOut size={14} /> Đăng xuất
            </button>
          </div>
        </div>
      </header>

      <main className="flex-1 max-w-[1400px] w-full mx-auto p-4 space-y-4">

        {/* Dashboard Cards */}
        <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
          <div className="bg-white p-4 border border-gray-300 shadow-sm flex items-center justify-between rounded-sm relative overflow-hidden group">
            <div className="absolute left-0 top-0 bottom-0 w-1 bg-blue-600"></div>
            <div>
              <p className="text-gray-500 font-semibold uppercase text-xs">Tổng số hồ sơ</p>
              <p className="text-2xl font-bold text-gray-800 mt-1">{stats.total}</p>
            </div>
            <div className="bg-blue-50 p-2 rounded text-blue-600">
              <FileText size={20} />
            </div>
          </div>

          <div className="bg-white p-4 border border-gray-300 shadow-sm flex items-center justify-between rounded-sm relative overflow-hidden">
             <div className="absolute left-0 top-0 bottom-0 w-1 bg-red-600"></div>
            <div>
              <p className="text-gray-500 font-semibold uppercase text-xs">Đang bị ngăn chặn</p>
              <p className="text-2xl font-bold text-red-700 mt-1">{stats.blocked}</p>
            </div>
            <div className="bg-red-50 p-2 rounded text-red-600">
              <Lock size={20} />
            </div>
          </div>

          <div className="bg-white p-4 border border-gray-300 shadow-sm flex items-center justify-between rounded-sm relative overflow-hidden">
             <div className="absolute left-0 top-0 bottom-0 w-1 bg-green-600"></div>
            <div>
              <p className="text-gray-500 font-semibold uppercase text-xs">Đã giải ngăn chặn</p>
              <p className="text-2xl font-bold text-green-700 mt-1">{stats.unblocked}</p>
            </div>
            <div className="bg-green-50 p-2 rounded text-green-600">
              <Unlock size={20} />
            </div>
          </div>
        </div>

        {/* Toolbar & Filter */}
        <div className="bg-white border border-gray-300 shadow-sm rounded-sm">
           <div className="flex flex-col md:flex-row justify-between items-center gap-3 p-3">
              <div className="flex items-center gap-2 flex-1 w-full md:w-auto">
                <div className="relative flex-1 md:max-w-md">
                  <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none">
                    <Search className="h-4 w-4 text-gray-500" />
                  </div>
                  <input
                    type="text"
                    className="block w-full pl-9 pr-3 py-2 border border-gray-400 rounded-sm leading-5 bg-white placeholder-gray-500 focus:outline-none focus:ring-1 focus:ring-blue-600 focus:border-blue-600 sm:text-sm"
                    placeholder="Nhập tên, số tờ, số thửa, số GCN..."
                    value={searchTerm}
                    onChange={(e) => setSearchTerm(e.target.value)}
                  />
                </div>
                <button 
                  onClick={() => setShowFilters(!showFilters)}
                  className={`flex items-center gap-2 px-3 py-2 rounded-sm border transition-colors text-sm font-medium ${showFilters ? 'bg-blue-50 border-blue-300 text-blue-700' : 'bg-gray-50 border-gray-300 text-gray-600 hover:bg-gray-100'}`}
                  title="Bộ lọc nâng cao"
                >
                  <Filter size={16} /> <span className="hidden sm:inline">Bộ lọc</span>
                </button>
              </div>

              {canAdd && (
                <button
                  onClick={() => { setEditingRecord(undefined); setIsFormOpen(true); }}
                  className="flex items-center gap-2 bg-[#006699] text-white px-4 py-2 rounded-sm hover:bg-[#004d73] transition text-sm font-medium shadow-sm uppercase whitespace-nowrap"
                >
                  <Plus size={16} />
                  Thêm Mới
                </button>
              )}
           </div>

           {/* Advanced Filter Panel */}
           {showFilters && (
             <div className="p-4 border-t border-gray-200 bg-gray-50 animate-in slide-in-from-top-2 duration-200">
               <div className="flex justify-between items-center mb-3">
                  <h3 className="text-xs font-bold text-gray-500 uppercase tracking-wider">Tiêu chí lọc nâng cao</h3>
                  <button onClick={resetFilters} className="text-xs text-red-600 hover:text-red-800 flex items-center gap-1 hover:underline">
                      <XCircle size={14} /> Xóa điều kiện lọc
                  </button>
               </div>
               <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-4">
